import type { Drill } from "./types";

// Doctor / early drills, keyed by module slug — 25 per module.
// Pitched at a resident / junior physician: rounds presentations, SBAR handoffs,
// plain-language patient and family communication, escalations, consults,
// discharge summaries, and messages to nursing. Merged into course.ts.
export const DOCTOR_EARLY_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-doc-early-01","level":"early","profession":"doctor","title":"The buried one-liner on rounds","scenario":"You're presenting Mr. Alvarez on morning rounds. Your assessment is that he's ready for discharge today, but your draft walks through every lab and vital sign from the past three days before getting there.","task":"Write a 1-2 sentence opener that states your assessment and plan first.","tips":["First sentence = your conclusion: ready for discharge today.","The data is support — the attending will ask for what she needs.","Rounds move fast; the headline buys attention for the rest."],"focus":["structure","clarity"],"placeholder":"Mr. Alvarez is ready for discharge today —"},
    {"id":"lead-doc-early-02","level":"early","profession":"doctor","title":"The 3 a.m. call that buries the ask","scenario":"Your patient's blood pressure has been trending down for two hours and you want the attending to come assess her. On the phone, you tend to start with the whole admission story before saying why you called.","task":"Write the first two sentences of the call, leading with why you're calling and what you need.","tips":["Name the ask in sentence one: I need you to see her.","The admission story is background — it comes after, briefly.","At 3 a.m., the listener needs the point before the plot."],"focus":["clarity","impact"],"placeholder":"Dr. Osei, I'm calling because I need you to see Ms. Tran — her blood pressure is dropping."},
    {"id":"lead-doc-early-03","level":"early","profession":"doctor","title":"The consult page with no question","scenario":"You're paging cardiology about a patient with new chest pain. Your draft summarizes the entire hospital course before mentioning what you actually want from them.","task":"Write a 2-3 sentence consult request that puts your question first.","tips":["Lead with the question you need answered.","Add only the details that bear on that question.","A consultant triages by the first line — make it the ask."],"focus":["clarity","concision"]},
    {"id":"lead-doc-early-04","level":"early","profession":"doctor","title":"The handoff that starts with the stable ones","scenario":"You're signing out ten patients at shift change. One is genuinely sick — you're worried he may need the ICU overnight. Your instinct is to go down the list in room order.","task":"Write the opening line of your handoff that flags the sickest patient first.","tips":["Sickest first, always — room order is for the chart, not the handoff.","Name the risk and what the covering doctor should do about it.","If they remember one line, it should be this one."],"focus":["structure","impact"],"placeholder":"Start with bed 7 — he's my one watcher tonight."},
    {"id":"lead-doc-early-05","level":"early","profession":"doctor","title":"The family update after surgery","scenario":"Ms. Ford's daughter has been in the waiting room for three hours. The operation went well and her mother is in recovery. You tend to start with procedural details before the news.","task":"Write a 1-2 sentence update that leads with the headline the daughter is waiting for.","tips":["Say the outcome first: it went well, she's safe.","Every second before the headline is agony for the listener.","Details are welcome after relief, not before it."],"focus":["clarity","audience"],"placeholder":"The surgery went well and your mother is doing fine —"},
    {"id":"lead-doc-early-06","level":"early","profession":"doctor","title":"The discharge summary that opens with the point","scenario":"You're writing the discharge summary for a patient admitted with pneumonia, treated, and improved. The next doctor needs the arc in one line, but your draft starts with the emergency-department triage note.","task":"Write a one-sentence opening that states why he came in, what was done, and how he left.","tips":["Admission reason, treatment, outcome — one sentence.","The next reader has ninety seconds; front-load the arc.","Day-by-day detail belongs in the body, not the opening."],"focus":["structure","concision"]},
    {"id":"lead-doc-early-07","level":"early","profession":"doctor","title":"The order change the nurse has to hunt for","scenario":"You're messaging the night nurse that Mr. Odom's IV fluids should stop at midnight and he can have water. Your draft opens with two sentences of background about his kidney labs.","task":"Rewrite the message so the action item is the first sentence.","tips":["Lead with what changes and when: stop fluids at midnight.","The lab reasoning is optional context, not the headline.","A busy nurse acts on the first line — make it the instruction."],"focus":["clarity","concision"]},
    {"id":"lead-doc-early-08","level":"early","profession":"doctor","title":"The escalation you keep softening","scenario":"Something about the patient in bed 12 worries you — she's more confused than she was an hour ago. Your draft message to your senior opens with hedges and history instead of the concern.","task":"Write a message that leads with the worry and the ask in the first sentence.","tips":["Say it plainly: I'm worried about bed 12, and here's why.","Ask for what you want: come see her with me now.","Softening an escalation defeats its purpose."],"focus":["clarity","impact"],"placeholder":"I'm worried about bed 12 — she's newly confused. Can you come see her with me now?"},
    {"id":"lead-doc-early-09","level":"early","profession":"doctor","title":"The lab callback","scenario":"You're calling a clinic patient about her thyroid test. The result is normal and nothing needs to change. You tend to explain what the test measures before saying the result.","task":"Write your opening two sentences, leading with the result and what it means for her.","tips":["The word she's waiting for is 'normal' — say it first.","What the test measures is trivia unless she asks.","End with what, if anything, she needs to do: nothing."],"focus":["clarity","audience"]},
    {"id":"lead-doc-early-10","level":"early","profession":"doctor","title":"The pharmacy question in paragraph three","scenario":"You need pharmacy to confirm whether two of your patient's medications can safely be given together tonight. Your draft message recounts the whole medication list before the question appears.","task":"Rewrite the message so the question is sentence one.","tips":["Question first, then only the two medications it concerns.","The full list is available in the chart — don't paste it.","A clear question gets answered before the shift ends."],"focus":["concision","clarity"]},
    {"id":"lead-doc-early-11","level":"early","profession":"doctor","title":"The admission call from the ED","scenario":"You're in the emergency department calling the medicine team to admit a patient. The accepting resident needs to hear first that this is an admission request — but you tend to launch into the full story.","task":"Write a one-sentence opener that names the ask, the patient, and the reason.","tips":["Say 'I have an admission for you' before anything else.","One line: who the patient is and why they're staying.","The detailed story follows once the frame is set."],"focus":["structure","clarity"],"placeholder":"I have an admission for you: a 68-year-old with a leg infection that isn't responding to oral antibiotics."},
    {"id":"lead-doc-early-12","level":"early","profession":"doctor","title":"The imaging request that wanders","scenario":"You're calling radiology to ask them to move up a CT scan, because the surgical decision depends on it today. Your draft explains the whole case history before making the request.","task":"Write a 2-sentence request: the ask first, then the one reason that justifies it.","tips":["Lead with the specific ask: move the scan to this morning.","Give the one reason that matters — a decision waits on it.","History that doesn't change their answer is noise."],"focus":["clarity","impact"]},
    {"id":"lead-doc-early-13","level":"early","profession":"doctor","title":"The scheduling email","scenario":"A clinic patient needs her follow-up moved from six weeks out to two, and only the scheduler can do it. Your email draft opens with the patient's whole story.","task":"Write an email opener that puts the ask and the timeframe first.","tips":["First line: what you need changed and by when.","The scheduler needs the ask, not the clinical reasoning.","One sentence of context is plenty — after the request."],"focus":["clarity","concision"]},
    {"id":"lead-doc-early-14","level":"early","profession":"doctor","title":"The shift-swap text","scenario":"You need a co-resident to swap call with you this Saturday. Your draft text starts with three sentences of apology and explanation before the ask.","task":"Write a 1-2 sentence text: the ask first, then one line of context.","tips":["Lead with the request and the date.","Offer the trade in the same breath — make yes easy.","Cut the apology spiral; it's a normal ask."],"focus":["concision","clarity"],"placeholder":"Any chance you could take my Saturday call? I'll cover your next weekend —"},
    {"id":"lead-doc-early-15","level":"early","profession":"doctor","title":"Overnight events, one headline","scenario":"At morning rounds you report overnight events. Almost everything was quiet, but one patient spiked a fever and had blood cultures drawn. Your habit is to recite the quiet rooms first.","task":"Write the opening line that leads with the one event that matters.","tips":["Headline the exception, not the routine.","'Everyone else was quiet' is one clause, not ten updates.","Lead with what was done about it, not just that it happened."],"focus":["structure","concision"]},
    {"id":"lead-doc-early-16","level":"early","profession":"doctor","title":"The conference case with a buried lesson","scenario":"You're presenting a case at noon conference. The reason it's worth presenting: the diagnosis was missed twice because of a look-alike rash. Your draft saves that for the final slide.","task":"Write an opening 1-2 sentences that lead with why this case matters.","tips":["Tell the room up front what they'll learn.","A stated lesson makes every detail land as evidence.","Suspense is for novels; teaching rewards the reveal first."],"focus":["structure","impact"]},
    {"id":"lead-doc-early-17","level":"early","profession":"doctor","title":"Telling the attending about your mistake","scenario":"You ordered a morning medication for the wrong patient; the pharmacist caught it and no harm resulted. You need to tell your attending, and your instinct is to open with context and mitigation.","task":"Write 2-3 sentences that state what happened in the first sentence.","tips":["Lead with the fact: I made a medication error this morning.","Then the status: caught before administration, no harm.","Owning it up front reads as integrity; burying it reads as spin."],"focus":["clarity","impact"],"placeholder":"I need to tell you about a medication error I made this morning."},
    {"id":"lead-doc-early-18","level":"early","profession":"doctor","title":"The question the patient actually asked","scenario":"During your exam a patient asks directly: \"Is this mole something to worry about?\" You've looked at it and the plan is a routine dermatology referral to be safe. You tend to explain the referral process before answering.","task":"Write a spoken answer that responds to the worry first, then gives the plan.","tips":["Answer the question asked: it doesn't look worrying.","Then the plan, framed as caution rather than alarm.","Process details before the answer feel like evasion."],"focus":["clarity","audience"]},
    {"id":"lead-doc-early-19","level":"early","profession":"doctor","title":"The discharge blocker","scenario":"Mr. Idris is medically ready to leave but can't go home without a walker and a home-safety check, which only the social worker can arrange. Your message to her opens with his hospital course.","task":"Rewrite the message so the first sentence names what you need and by when.","tips":["Lead with the two items and the target date.","She doesn't need his clinical story — she needs her to-do list.","Make the deadline explicit or it becomes 'whenever'."],"focus":["clarity","impact"]},
    {"id":"lead-doc-early-20","level":"early","profession":"doctor","title":"The if-then that leads","scenario":"You're writing the sign-out entry for a patient who might drop his oxygen level overnight. The covering resident needs the instruction, not the story of how he got here.","task":"Write a one-line sign-out that leads with the if-then instruction.","tips":["Format: if X happens, do Y, call Z.","Put the trigger number in the line, not in your head.","History goes in the chart; the sign-out is for action."],"focus":["structure","precision"],"placeholder":"If his oxygen needs go above 4L, call the ICU team —"},
    {"id":"lead-doc-early-21","level":"early","profession":"doctor","title":"The portal reply with the answer up top","scenario":"A patient messaged the portal asking whether her cholesterol result means she needs medication. It doesn't — the plan is diet changes and a recheck in three months. Your draft explains cholesterol biology first.","task":"Write a reply whose first sentence answers her question.","tips":["Sentence one: no, you don't need medication.","Then the plan: what she does and when you'll recheck.","Biology lessons are optional reading, below the answer."],"focus":["clarity","audience"]},
    {"id":"lead-doc-early-22","level":"early","profession":"doctor","title":"Two options, one decision","scenario":"Your attending is between cases and has thirty seconds. You need her pick: discharge Mr. Bell today with close follow-up, or keep him one more night. Your instinct is to re-present the whole case.","task":"Write a 2-sentence message: the decision needed first, then the one-line tradeoff.","tips":["Name the decision in sentence one, as an either/or.","One sentence of tradeoff — the thing that makes it close.","Bounded choices get answered in thirty seconds; essays don't."],"focus":["clarity","concision"],"placeholder":"Need your call on Mr. Bell: discharge today with Friday follow-up, or one more night?"},
    {"id":"lead-doc-early-23","level":"early","profession":"doctor","title":"The family meeting headline","scenario":"You're opening a family meeting about Mrs. Kaur, whose condition has stabilized but who will need weeks of rehabilitation. The family fears the worst. Your draft opening recaps two weeks of events.","task":"Write an opening 1-2 sentences that state where things stand now.","tips":["Lead with the present: she's stable, and here's what comes next.","A scared family can't absorb history until the headline lands.","Keep the first sentence free of medical vocabulary."],"focus":["clarity","audience"]},
    {"id":"lead-doc-early-24","level":"early","profession":"doctor","title":"Asking to be supervised","scenario":"A patient needs a bedside procedure you've done only once, and your senior is on the unit. You want to ask her to supervise, but your draft message meanders through your training history.","task":"Write a message that leads with the ask and when you need her.","tips":["First line: the procedure, the patient, and 'can you supervise'.","Give the time window so she can say yes to something specific.","Your experience level is one clause, not a paragraph."],"focus":["clarity","concision"]},
    {"id":"lead-doc-early-25","level":"early","profession":"doctor","title":"The post-call recap","scenario":"After a heavy call night you're emailing the day team a recap. The single most important development: a new admission is scheduled for surgery at noon. Your draft is chronological from 6 p.m. onward.","task":"Write the opening line that leads with the noon surgery, then signals the rest is routine.","tips":["Lead with the item that changes someone's morning.","'Everything else below is routine' earns the reader's trust.","Chronology is how you lived it, not how they should read it."],"focus":["structure","impact"],"placeholder":"Headline: the new admission in bed 14 goes to surgery at noon —"}
  ],
  "start-with-the-audience": [
    {"id":"audience-doc-early-01","level":"early","profession":"doctor","title":"Pneumonia, in plain words","scenario":"You just told the attending: \"Right lower lobe consolidation on imaging, consistent with community-acquired pneumonia; starting antibiotics.\" Now the patient asks you what's going on.","task":"Explain the diagnosis and plan in 2-3 sentences a patient with no medical background can follow.","tips":["Swap the anatomy for plain words: an infection in your lung.","Say what it means for him: treatment, and roughly how long.","Test: could he repeat it accurately to his wife tonight?"],"focus":["audience","clarity"],"placeholder":"You have pneumonia — an infection in your lung."},
    {"id":"audience-doc-early-02","level":"early","profession":"doctor","title":"Same news, different listener","scenario":"Mr. Roy's tests show his kidney function has worsened; the plan is IV fluids and daily labs. You presented it to the attending in numbers. His wife, waiting in the hallway, asks how he's doing.","task":"Write what you'd say to his wife in 2-3 sentences — her stake, not the lab values.","tips":["Her question is 'is he okay and what happens now' — answer that.","Translate the plan into what she'll see: fluids through the drip, daily blood tests.","Numbers only if they carry meaning she can use."],"focus":["audience","clarity"]},
    {"id":"audience-doc-early-03","level":"early","profession":"doctor","title":"Consent without jargon","scenario":"You're consenting a patient for a lumbar puncture. Your usual script leans on terms like \"aseptic technique,\" \"post-procedural headache,\" and \"contraindications.\" The patient looks lost.","task":"Rewrite the core explanation — what you'll do, why, and the main risk — in three plain sentences.","tips":["Describe the action physically: a thin needle in the lower back to collect fluid.","Name the why in terms of his question: to find out what's causing this.","One honest main risk, in words he'd use himself."],"focus":["audience","clarity"]},
    {"id":"audience-doc-early-04","level":"early","profession":"doctor","title":"What the nurse needs to watch","scenario":"You're worried your patient could bleed after his procedure, and you want the night nurse alert to it. Your draft note explains the underlying physiology at length.","task":"Write a 2-3 sentence note telling the nurse exactly what to watch for and when to call you.","tips":["Lead with observable signs, not mechanisms.","Give the threshold that triggers a call — and your number.","She needs a watchlist, not a lecture."],"focus":["audience","precision"]},
    {"id":"audience-doc-early-05","level":"early","profession":"doctor","title":"Discharge instructions someone can follow","scenario":"Your patient is going home after a stomach bug with instructions you drafted: \"Advance diet as tolerated, maintain adequate hydration, return for signs of clinical deterioration.\" He's 78 and asked his granddaughter to explain them.","task":"Rewrite the instructions in plain, specific language he can act on.","tips":["Turn each abstraction into an action: start with soup and toast; drink a glass of water every hour you're awake.","'Deterioration' means nothing — list the two or three signs that should trigger a call.","Short sentences; one instruction each."],"focus":["audience","precision"],"placeholder":"Start with small, plain meals — soup, toast, rice."},
    {"id":"audience-doc-early-06","level":"early","profession":"doctor","title":"The teenager in room 4","scenario":"Your 16-year-old patient with newly diagnosed asthma tunes out when you talk to her mother instead of her. She's the one who needs to understand her inhaler plan.","task":"Write 2-3 sentences explaining the plan directly to her, at her level without being condescending.","tips":["Talk to her, not about her — 'you', not 'she'.","Anchor it to her life: sports practice, school mornings.","Respect reads as plain talk, not baby talk."],"focus":["audience","clarity"]},
    {"id":"audience-doc-early-07","level":"early","profession":"doctor","title":"Through the interpreter","scenario":"You're explaining a medication change through a phone interpreter. Your usual long, comma-spliced sentences fall apart when translated in chunks.","task":"Rewrite the explanation as three short, self-contained sentences that translate cleanly.","tips":["One idea per sentence; the interpreter relays them one at a time.","Cut idioms and figures of speech — they don't survive translation.","Pause points are part of the writing: end each sentence somewhere complete."],"focus":["audience","concision"]},
    {"id":"audience-doc-early-08","level":"early","profession":"doctor","title":"The consult that respects their time","scenario":"You're requesting a neurology consult. Your draft pastes the entire three-day hospital course. The neurologist needs your specific question and only the details that bear on it.","task":"Write a 3-4 sentence consult request built around what the consultant needs.","tips":["Open with the question you want answered.","Include only findings that change their thinking.","The chart holds everything else — point, don't paste."],"focus":["audience","concision"],"placeholder":"Question for you: is this new weakness something you'd scan tonight?"},
    {"id":"audience-doc-early-09","level":"early","profession":"doctor","title":"Why nothing to eat after midnight","scenario":"Your patient keeps asking why he can't have breakfast before his procedure. Your first answer — \"aspiration risk under sedation\" — didn't land.","task":"Explain the rule in 1-2 sentences that make the reason concrete for him.","tips":["Make the mechanism physical: food in the stomach can end up in the lungs while you're asleep.","Connect it to his interest: an empty stomach keeps the procedure safe and on time.","If the reason lands, the rule enforces itself."],"focus":["audience","clarity"],"placeholder":"While you're sedated, anything in your stomach could slip into your lungs —"},
    {"id":"audience-doc-early-10","level":"early","profession":"doctor","title":"The family member who's a physician","scenario":"Your patient's daughter introduces herself as an anesthesiologist and asks for an update. Your plain-language script will sound evasive to her; your rounds presentation would serve her better.","task":"Write a 2-3 sentence update calibrated for a physician family member.","tips":["Calibrate up: give the clinical picture with real terms and numbers.","She's still family — include the trajectory, not just the data.","Watch for the moment she asks as a daughter, not a doctor."],"focus":["audience","precision"]},
    {"id":"audience-doc-early-11","level":"early","profession":"doctor","title":"The delayed scan","scenario":"Your patient was told her MRI would happen this morning; it's now bumped to tonight. She's frustrated and asks why. The real reason involves scanner queues and an emergency case that took priority.","task":"Write what you'd say — her concern first, the honest reason, and what happens next.","tips":["Acknowledge the cost to her before explaining the system.","One honest sentence of reason beats three of process.","End with what's certain: the new time, and that results follow tomorrow."],"focus":["audience","clarity"]},
    {"id":"audience-doc-early-12","level":"early","profession":"doctor","title":"The new pill, explained","scenario":"You're starting your 82-year-old clinic patient on a blood-pressure medication. Your draft mentions \"titration\" and \"orthostatic hypotension.\" She takes careful notes in a small notebook.","task":"Explain the new medication in three sentences she can act on: what it's for, when to take it, what to watch for.","tips":["One sentence each: purpose, routine, warning sign.","'Orthostatic hypotension' becomes: you might feel dizzy when you stand up quickly.","Write it the way she'd copy it into the notebook."],"focus":["audience","precision"]},
    {"id":"audience-doc-early-13","level":"early","profession":"doctor","title":"Day-one intern, zero shorthand","scenario":"You're orienting a brand-new intern to your team's workflow. Your draft is full of unit shorthand — \"the purple list,\" \"the usual fast-track,\" names without roles.","task":"Rewrite a 3-4 sentence orientation that assumes no local knowledge.","tips":["Expand every piece of shorthand the first time you use it.","Names come with roles: 'Rosa, the charge nurse'.","The curse of knowledge hides exactly where you stopped noticing it."],"focus":["audience","clarity"]},
    {"id":"audience-doc-early-14","level":"early","profession":"doctor","title":"What the case manager actually needs","scenario":"You're updating the case manager about Mr. Green's discharge. Your draft details his medical course. She needs the discharge date, the equipment, and the services — the levers she controls.","task":"Write a 2-3 sentence update framed around the decisions she has to make.","tips":["Lead with the date and what has to be in place by then.","Translate the medicine into logistics: walker, home nursing, transport.","Her question is 'what do I need to arrange' — answer exactly that."],"focus":["audience","clarity"],"placeholder":"Targeting Thursday discharge — he'll need a walker and one home-nursing visit set up by then."},
    {"id":"audience-doc-early-15","level":"early","profession":"doctor","title":"Watch and wait, without alarm","scenario":"The plan for Mrs. Osei is observation: no new treatment, repeat labs tomorrow. Her son hears \"the doctors are doing nothing.\"","task":"Explain watchful waiting in 2-3 sentences that make the monitoring feel active and deliberate.","tips":["Name what IS happening: checks every four hours, fresh labs at dawn.","Explain why waiting is the treatment right now — acting early could do harm.","Give him the tripwire: what would make the plan change."],"focus":["audience","clarity"],"placeholder":"We're not doing nothing — we're watching her closely on purpose."},
    {"id":"audience-doc-early-16","level":"early","profession":"doctor","title":"The incidental finding","scenario":"A scan done for a cough also mentioned a small, almost certainly benign cyst that needs a routine follow-up image next year. Your patient read the report online and is alarmed by the word \"lesion.\"","task":"Write a 2-3 sentence explanation that addresses the fear before the logistics.","tips":["Meet the word head-on: 'lesion' is report language for 'a spot', not a verdict.","Say what the team actually thinks it is and how confident they are.","Then the plan — and why a year's wait is a sign of low concern, not neglect."],"focus":["audience","clarity"]},
    {"id":"audience-doc-early-17","level":"early","profession":"doctor","title":"What borderline means","scenario":"Your patient's blood-sugar result is borderline — not diabetes, but worth rechecking in three months alongside some diet changes. He asks, \"So do I have it or not?\"","task":"Answer his actual question in plain terms, then say what happens next.","tips":["Answer the binary first: no, you don't have diabetes today.","Then the honest nuance: you're in the warning zone, and it's reversible.","Make the next step feel like his move, with a date attached."],"focus":["audience","clarity"],"placeholder":"No — you don't have diabetes. You're in the warning zone, and —"},
    {"id":"audience-doc-early-18","level":"early","profession":"doctor","title":"The worried parent","scenario":"A father brings his 6-year-old in with a high fever. The workup points to a routine virus that will pass on its own. He expected antibiotics and looks unconvinced.","task":"Explain the diagnosis and home plan in 2-3 sentences that speak to his worry, not your workup.","tips":["His real question is 'is my kid okay' — answer it first.","Explain what he can do at home; helplessness fuels the antibiotic ask.","Give the return triggers: exactly what should bring them back."],"focus":["audience","clarity"]},
    {"id":"audience-doc-early-19","level":"early","profession":"doctor","title":"The work note","scenario":"Your patient needs a letter for her employer saying she can return to work with a lifting restriction for two weeks. Your draft reads like a chart note, full of clinical language.","task":"Rewrite the key sentences in language an HR manager can read and apply.","tips":["The reader needs three things: can she work, what's restricted, until when.","Cut diagnosis details she may not want shared — the restriction is the point.","Plain nouns: 'no lifting over 10 pounds', not 'activity modification'."],"focus":["audience","precision"]},
    {"id":"audience-doc-early-20","level":"early","profession":"doctor","title":"What the attending listens for","scenario":"You're presenting a new admission: a man with dehydration from food poisoning, on IV fluids overnight, likely home tomorrow. Your draft recites every normal lab. Your attending has told you she wants assessment and plan — data only where it changes a decision.","task":"Write the assessment-and-plan in 2-3 sentences pitched at what she needs.","tips":["Lead with your read: straightforward dehydration, responding to fluids.","Mention only the results that could change the plan.","Her altitude is decisions, not data — meet her there."],"focus":["audience","structure"]},
    {"id":"audience-doc-early-21","level":"early","profession":"doctor","title":"Why antibiotics won't help","scenario":"Your clinic patient with a week of cold symptoms asks for antibiotics. Everything points to a virus. \"It's viral\" hasn't convinced anyone yet.","task":"Write a 2-3 sentence explanation that connects the reason to his goal — feeling better sooner.","tips":["Frame it around his interest: antibiotics won't shorten this, and can add side effects.","Give him something active: what actually helps, starting today.","Name the escalation path so 'no antibiotics' doesn't mean 'no plan'."],"focus":["audience","impact"]},
    {"id":"audience-doc-early-22","level":"early","profession":"doctor","title":"The ICU transfer","scenario":"Mr. Duval needs closer monitoring and is moving to the intensive care unit tonight. To his family, \"ICU\" means one thing: he's dying. That's not the situation — it's a precaution and closer nursing care.","task":"Write 2-3 sentences to the family that get ahead of what \"ICU\" means to them.","tips":["Name the fear before they do: the ICU sounds frightening, so say what it is here — one nurse, constant monitoring.","Be honest about why: he needs closer watching than this floor can give.","Tell them what stays the same: visiting, updates, the same team involved."],"focus":["audience","clarity"],"placeholder":"I want to explain the move before the word ICU does —"},
    {"id":"audience-doc-early-23","level":"early","profession":"doctor","title":"The portal message, matched","scenario":"A patient messages: \"my report says ejection fraction 55% is that bad???\" It's a normal result. Your draft reply reads like a textbook paragraph.","task":"Write a reply matched to her level of worry and vocabulary, answer first.","tips":["First sentence: that number is normal — good news.","Translate once, briefly: it measures how well the heart pumps.","Match her register: short, warm, direct — not a lecture."],"focus":["audience","concision"],"placeholder":"Good news — 55% is a normal result."},
    {"id":"audience-doc-early-24","level":"early","profession":"doctor","title":"The transfer report to the paramedics","scenario":"You're sending a stable patient to another hospital by ambulance and giving the transport crew a verbal report. They need what matters in transit — not the diagnostic reasoning.","task":"Write a 3-sentence report focused on what the crew must know and do en route.","tips":["Their frame is the next ninety minutes: current status, lines and oxygen, what could change.","Give the one action instruction: what to do and who to call if it does.","Diagnosis history matters only where it predicts a transit problem."],"focus":["audience","precision"]},
    {"id":"audience-doc-early-25","level":"early","profession":"doctor","title":"Teaching the med student","scenario":"Your third-year student asks why the team stopped a medication. You know the full pharmacology; she needs the one level that helps her present the patient tomorrow.","task":"Explain the decision in 2-3 sentences at teaching altitude — the principle, not the rabbit hole.","tips":["Give the rule she can reuse, then this case as the example.","Skip the exceptions on the first pass — depth on request.","Good teaching ends where her tomorrow begins: what she'll say on rounds."],"focus":["audience","structure"]}
  ],
  "structure-that-carries": [
    {"id":"structure-doc-early-01","level":"early","profession":"doctor","title":"The SBAR that skips the S","scenario":"You're handing off a deteriorating patient to the covering resident, but your report jumps between symptoms, history, and your worry without an order. She keeps asking you to back up.","task":"Structure the handoff as Situation, Background, Assessment, Recommendation in 4-5 sentences.","tips":["One sentence per SBAR slot; label them in your head as you go.","Situation is now, Background is how we got here — don't blend them.","End on the Recommendation: the specific thing you want done."],"focus":["structure","clarity"],"placeholder":"Situation: bed 9's blood pressure has dropped over the last hour."},
    {"id":"structure-doc-early-02","level":"early","profession":"doctor","title":"One governing idea for rounds","scenario":"Your presentation of a complex patient lists eight problems with equal weight. The attending can't tell what the day is actually about.","task":"Write a 2-3 sentence assessment led by one governing idea, with the problems grouped under it.","tips":["Find the one sentence the day turns on, and say it first.","Group the eight problems into at most three themes.","Equal weight for everything means emphasis for nothing."],"focus":["structure","clarity"]},
    {"id":"structure-doc-early-03","level":"early","profession":"doctor","title":"PREP for the bedside question","scenario":"On rounds the attending asks, \"Should we anticoagulate this patient?\" You know the answer but ramble through pros and cons without landing.","task":"Answer using Point, Reason, Example, Point in 3-4 sentences.","tips":["Point first: yes (or no), we should.","One reason, then one concrete supporting fact.","Close by restating the point so it sticks."],"focus":["structure","impact"],"placeholder":"Yes, I'd anticoagulate her. The main reason is —"},
    {"id":"structure-doc-early-04","level":"early","profession":"doctor","title":"Grouping the problem list","scenario":"Your admission note lists eleven active problems in the order you thought of them: potassium, then a rash, then chest pain, then a medication refill. The next reader can't find the thread.","task":"Regroup the eleven into 3 labeled buckets and write the bucket headers.","tips":["Cluster by system or by urgency — pick one logic and hold it.","Name each bucket so a reader can navigate without reading every line.","The acute, decision-driving problems lead; the housekeeping trails."],"focus":["structure","clarity"]},
    {"id":"structure-doc-early-05","level":"early","profession":"doctor","title":"SCQA for the consult","scenario":"You're framing a consult request to gastroenterology. You launch straight into your question, and the consultant has no idea what changed to prompt it.","task":"Frame the request as Situation, Complication, Question in 3 sentences.","tips":["Situation: the stable baseline. Complication: what changed.","The Question falls out naturally once the tension is set.","Skip the full history — SCQA is the shortcut to the ask."],"focus":["structure","clarity"]},
    {"id":"structure-doc-early-06","level":"early","profession":"doctor","title":"The discharge summary with no spine","scenario":"Your discharge summary is a wall of chronological text. The next doctor needs to find the diagnosis, the treatment, and the follow-up fast, but they're scattered throughout.","task":"Draft 3 section headers and the one-line content each should lead with.","tips":["Standard spine: why he came, what we did, what's next.","Each section opens with its own headline sentence.","Chronology lives inside sections, not as the whole structure."],"focus":["structure","clarity"]},
    {"id":"structure-doc-early-07","level":"early","profession":"doctor","title":"Three reasons, not thirty facts","scenario":"You're arguing to the attending that a patient should stay another night. You have a dozen data points but no scaffold, so it sounds like anxious over-reporting.","task":"Structure the case as one claim supported by exactly three reasons.","tips":["State the claim, then 'for three reasons' — and name them.","Each reason absorbs several data points; don't list raw numbers.","Three is memorable; twelve is noise."],"focus":["structure","concision"],"placeholder":"I'd keep him one more night for three reasons:"},
    {"id":"structure-doc-early-08","level":"early","profession":"doctor","title":"The teaching case, sequenced","scenario":"You're presenting a case at morning report. Your slides jump between the diagnosis, the labs, and the lesson with no arc, and the room loses the thread.","task":"Outline a 4-beat structure for the case: setup, turn, resolution, lesson.","tips":["Each beat is one line; the arc carries the audience.","The 'turn' is the moment the diagnosis became clear — build to it.","End on the transferable lesson, stated plainly."],"focus":["structure","impact"]},
    {"id":"structure-doc-early-09","level":"early","profession":"doctor","title":"The family meeting agenda","scenario":"You're leading a family meeting about goals of care. Without a plan you'll wander, and the family will leave more confused than when they arrived.","task":"Write a 3-part spoken agenda you'll state at the top of the meeting.","tips":["Tell them the shape first: where we are, options, what we decide today.","A stated agenda gives a frightened family something to hold.","Three parts, one sentence each — then walk through them."],"focus":["structure","audience"]},
    {"id":"structure-doc-early-10","level":"early","profession":"doctor","title":"The nurse message with two asks buried","scenario":"Your message to the nurse contains two separate actions — hold the morning insulin, and recheck the sugar at noon — but they're tangled inside a paragraph of reasoning.","task":"Rewrite as a labeled list: the two actions, then the one-line reason.","tips":["Actions as a numbered list; reason as a footnote.","Structure prevents the second ask from being missed.","One idea per line beats one paragraph with everything in it."],"focus":["structure","clarity"],"placeholder":"Two things: 1) hold the morning insulin, 2) recheck her sugar at noon."},
    {"id":"structure-doc-early-11","level":"early","profession":"doctor","title":"Presenting the plan by problem","scenario":"Your assessment-and-plan lumps everything into one paragraph. The attending wants each problem stated, then its plan — a clean problem-plan pairing.","task":"Restructure two of the problems into the 'problem: plan' format, one line each.","tips":["Name the problem, colon, then the specific action.","Keep the pairing tight — no history between problem and plan.","This format lets the team edit your plan line by line."],"focus":["structure","precision"]},
    {"id":"structure-doc-early-12","level":"early","profession":"doctor","title":"The chronological trap","scenario":"Explaining a complicated overnight to the day team, you narrate hour by hour. By 4 a.m. in your story they've lost track of what actually matters.","task":"Restructure the night around 'the three things that changed', not the timeline.","tips":["Lead with what's different this morning, not when it happened.","Three changes, each with what you did about it.","Timeline is your memory aid, not their briefing."],"focus":["structure","concision"]},
    {"id":"structure-doc-early-13","level":"early","profession":"doctor","title":"The referral letter outline","scenario":"You're writing a referral letter to a specialist clinic. Your draft mixes the reason, the history, and the question in no clear order, so the triaging clinician has to hunt.","task":"Write the 4 section headers a clean referral letter should have.","tips":["Reason for referral leads — the triage nurse reads that first.","Relevant history next, filtered to what bears on the question.","Your specific question, then what you've already tried."],"focus":["structure","clarity"]},
    {"id":"structure-doc-early-14","level":"early","profession":"doctor","title":"The if-then ladder","scenario":"You're leaving overnight instructions for a patient who could go one of three ways: stable, worse breathing, or worse pain. Your prose blurs the branches together.","task":"Structure the instructions as three clean if-then branches.","tips":["One line per branch: if X, do Y, call Z.","Order the branches by likelihood or by severity — pick one.","A branch the covering doctor can scan beats a paragraph they must parse."],"focus":["structure","precision"],"placeholder":"If breathing worsens (over 4L oxygen): call the ICU team."},
    {"id":"structure-doc-early-15","level":"early","profession":"doctor","title":"Signposting the long update","scenario":"You're giving the family a five-minute update covering the surgery, recovery, and next week. Without signposts they can't tell when one topic ends and the next begins.","task":"Write the three signpost sentences that mark the transitions in your update.","tips":["'First, the surgery itself' — name each section as you enter it.","Signposts let a stressed listener follow without notes.","Three clean transitions beat one seamless blur."],"focus":["structure","audience"]},
    {"id":"structure-doc-early-16","level":"early","profession":"doctor","title":"The morning report, front-loaded","scenario":"You're reporting overnight admissions. You bury the one unstable patient in the middle of five stable ones, ordered by admission time.","task":"Reorder the report so structure signals priority, and write the opening line.","tips":["Sickest first is itself a structure — use it deliberately.","Signal the tiers: 'one watcher, then four routine'.","Order carries meaning; don't waste it on chronology."],"focus":["structure","impact"]},
    {"id":"structure-doc-early-17","level":"early","profession":"doctor","title":"The pyramid for the tumor board","scenario":"You're summarizing a patient for the tumor board. You present findings bottom-up, building to a conclusion, but the board wants the conclusion first with support beneath.","task":"Invert it: write the top-line recommendation, then the 3 supporting points.","tips":["Recommendation first, evidence indented under it.","Three supports, each one line — the board drills where it wants.","Bottom-up is how you reasoned; top-down is how they decide."],"focus":["structure","clarity"]},
    {"id":"structure-doc-early-18","level":"early","profession":"doctor","title":"The medication reconciliation, grouped","scenario":"You're presenting a patient's fifteen home medications. Read as a flat list, it's unusable; the team can't see what's continued, held, or changed.","task":"Group the list into 3 buckets — continued, held, new — with a header line each.","tips":["The buckets are the message: what changed and why.","A grouped list answers the team's real question at a glance.","Alphabetical order helps a pharmacist; grouping helps the team."],"focus":["structure","clarity"]},
    {"id":"structure-doc-early-19","level":"early","profession":"doctor","title":"The escalation, structured","scenario":"You're escalating to your senior about a patient you're worried about, but you lead with data and never frame why it's an escalation. She's not sure if you want advice or action.","task":"Structure it as concern, evidence, ask in three sentences.","tips":["Concern first: I'm worried this is turning into X.","Evidence second: the two findings that worry you.","Ask last, and be specific: come now, or a phone order?"],"focus":["structure","clarity"],"placeholder":"I'm worried she's heading toward sepsis. Here's why:"},
    {"id":"structure-doc-early-20","level":"early","profession":"doctor","title":"The patient's whole story, in three acts","scenario":"A patient asks you to walk them through everything that's happened this admission. You have a lot to cover and no plan, so it comes out as a jumble.","task":"Sketch a 3-act structure — what brought you in, what we found, where we're headed.","tips":["Three acts a patient can hold: arrival, diagnosis, plan.","Each act is a couple of plain sentences, not a chart dump.","The structure itself is reassuring — it says someone's in control."],"focus":["structure","audience"]},
    {"id":"structure-doc-early-21","level":"early","profession":"doctor","title":"The problem that needs SCQA","scenario":"You're emailing your program director about a scheduling conflict that affects patient coverage. You open with the ask and it lands as a complaint with no context.","task":"Reframe as Situation, Complication, Question in 3 sentences.","tips":["Situation: the normal coverage plan everyone agreed to.","Complication: the conflict that broke it.","Question: the specific decision you need from her."],"focus":["structure","clarity"]},
    {"id":"structure-doc-early-22","level":"early","profession":"doctor","title":"The verbal order, read-back structured","scenario":"You're giving a verbal medication order to a nurse over the phone. You say it all in one breath and she has to ask you to repeat half of it.","task":"Structure the order into the discrete slots a nurse reads back: drug, dose, route, timing.","tips":["Say each slot distinctly, with a beat between them.","Structure enables the read-back that catches errors.","One run-on order is a safety risk; four clean slots isn't."],"focus":["structure","precision"],"placeholder":"Order: metoprolol, 25 milligrams, by mouth, now."},
    {"id":"structure-doc-early-23","level":"early","profession":"doctor","title":"The teaching point, scaffolded","scenario":"You're teaching the intern how to think through shortness of breath. You dump every cause you know, and it's a list with no organizing principle they can reuse.","task":"Give the intern a 3-category framework they can apply to the next patient.","tips":["Categories beat a flat list — heart, lungs, everything else.","A framework travels to the next case; a list doesn't.","Teach the buckets first; fill them with examples second."],"focus":["structure","audience"]},
    {"id":"structure-doc-early-24","level":"early","profession":"doctor","title":"The complex consult answer","scenario":"You're the one answering a consult for once — a junior asks your read on a rash. You have three thoughts and give them in a tangle, so the junior isn't sure what to do.","task":"Structure your answer as most-likely, what-to-do, when-to-worry in three sentences.","tips":["Lead with your leading diagnosis, stated plainly.","Then the concrete next step you'd take.","Close with the tripwire that should prompt a call back."],"focus":["structure","clarity"]},
    {"id":"structure-doc-early-25","level":"early","profession":"doctor","title":"The end-of-rotation summary","scenario":"You're handing off your whole panel to the incoming resident at rotation's end. Fifteen patients, no structure — she'll be lost by patient four.","task":"Write the organizing principle and the 3 tiers you'll sort the panel into.","tips":["Sort by attention needed: watchers, active, near-discharge.","State the tiers up front so she knows the map before the territory.","Within each tier, one line per patient — the headline only."],"focus":["structure","concision"]}
  ],
  "cut-to-the-bone": [
    {"id":"concise-doc-early-01","level":"early","profession":"doctor","title":"The hedged assessment","scenario":"Your note reads: \"It is possible that the patient may perhaps be experiencing what could potentially represent an early infection.\" The attending circles it and writes 'commit.'","task":"Rewrite the sentence stating your actual assessment in one clean line.","tips":["Stack of hedges — possible, may, perhaps, could, potentially — pick one or none.","If you believe it's early infection, say so and own the uncertainty once.","Confident and wrong is fixable; mush is not."],"focus":["concision","precision"],"placeholder":"This looks like an early infection."},
    {"id":"concise-doc-early-02","level":"early","profession":"doctor","title":"The 200-word sign-out line","scenario":"Your sign-out for one stable patient runs a full paragraph restating the entire admission. The covering doctor has nine other patients to read.","task":"Cut it to a single line: what to know and what to do overnight.","tips":["Stable patients get one line — status plus any tripwire.","The admission story is in the chart; don't recopy it.","If nothing's expected overnight, say 'no action expected' and stop."],"focus":["concision","clarity"]},
    {"id":"concise-doc-early-03","level":"early","profession":"doctor","title":"The nominalization pile-up","scenario":"Your discharge instruction says: \"Continuation of the utilization of the medication should be maintained pending the completion of the evaluation.\" A patient can't act on it.","task":"Rewrite it as a plain instruction in under twelve words.","tips":["Turn the noun-clumps back into verbs: keep taking, until we've checked.","'Continuation of the utilization' means 'keep taking'.","Read it aloud — if you'd never say it, don't write it."],"focus":["concision","clarity"],"placeholder":"Keep taking it until we recheck your blood."},
    {"id":"concise-doc-early-04","level":"early","profession":"doctor","title":"The meta-commentary on rounds","scenario":"You open every presentation with \"So I just wanted to quickly mention that I was going to go ahead and present...\" before any content. The attending is tapping her pen.","task":"Cut the throat-clearing and write the real first sentence.","tips":["'I wanted to mention that' — delete it, keep what follows.","Rounds reward the content, not the announcement of content.","Start where the information starts."],"focus":["concision","impact"]},
    {"id":"concise-doc-early-05","level":"early","profession":"doctor","title":"The redundant pair epidemic","scenario":"Your consult note is full of doublets: \"each and every,\" \"first and foremost,\" \"safe and stable,\" \"assess and evaluate.\" It reads padded.","task":"Rewrite three of these doublets as single words in a short sentence.","tips":["Each pair says one thing twice — keep the stronger half.","'Assess and evaluate' is just 'assess'.","Padding costs the reader time and costs you credibility."],"focus":["concision","precision"]},
    {"id":"concise-doc-early-06","level":"early","profession":"doctor","title":"The email that halves","scenario":"Your email to the clinic team about a schedule change is four sentences of context before the one that matters. The team skims and misses it.","task":"Cut the email to half its length, keeping only the action and one line of why.","tips":["Delete every sentence that doesn't change what they do.","The 'why' is one line, not a paragraph.","A shorter email gets read; a longer one gets deferred."],"focus":["concision","clarity"]},
    {"id":"concise-doc-early-07","level":"early","profession":"doctor","title":"The filler-laced phone order","scenario":"Over the phone you say: \"Yeah so basically what I think we should probably do at this point is maybe start some fluids or something.\" The nurse needs a clean order.","task":"Restate it as a crisp order with no filler.","tips":["Cut 'basically', 'probably', 'maybe', 'or something' — all four.","An order is a decision; hedged filler makes it a suggestion.","Say the drug, the amount, and 'now' or 'over an hour'."],"focus":["concision","precision"],"placeholder":"Start a liter of saline over the next hour."},
    {"id":"concise-doc-early-08","level":"early","profession":"doctor","title":"The over-explained normal result","scenario":"You're telling a patient their result is fine, but you spend a paragraph on what the test measures, how it's run, and what abnormal would mean. They just wanted 'it's normal.'","task":"Deliver the news and the next step in two short sentences.","tips":["Lead with 'it's normal' — that's the whole headline.","Only add detail if they ask for it.","The mechanism of the test is not the news."],"focus":["concision","audience"],"placeholder":"Your result came back normal — nothing to change."},
    {"id":"concise-doc-early-09","level":"early","profession":"doctor","title":"The bloated problem statement","scenario":"Your note says: \"The patient is a very pleasant gentleman who unfortunately has been dealing with a rather significant issue related to his blood pressure control over an extended period of time.\" The attending wants the fact.","task":"Rewrite it as one factual clinical line.","tips":["'Very pleasant', 'unfortunately', 'rather significant' — cut the color.","The reader needs the fact: long-standing poorly controlled high blood pressure.","Adjectives of sympathy don't belong in a problem statement."],"focus":["concision","precision"]},
    {"id":"concise-doc-early-10","level":"early","profession":"doctor","title":"The apology preamble","scenario":"Your message asking your senior a quick question opens with three sentences apologizing for bothering them and explaining why you feel bad about it.","task":"Cut the preamble and write just the question, politely.","tips":["One 'sorry to bother' at most; then the question.","The apology spiral wastes their time more than the question would.","A clear question respects their time better than an apology."],"focus":["concision","clarity"]},
    {"id":"concise-doc-early-11","level":"early","profession":"doctor","title":"The discharge summary that repeats itself","scenario":"Your discharge summary states the diagnosis in the header, again in the hospital course, and a third time in the plan — each time slightly differently, which invites confusion.","task":"Rewrite so the diagnosis appears once, cleanly, and the other mentions point back to it.","tips":["Say it once, exactly, in the right place.","Three slightly different phrasings read as three different claims.","Cross-reference instead of restating."],"focus":["concision","precision"]},
    {"id":"concise-doc-early-12","level":"early","profession":"doctor","title":"The list that should be a sentence","scenario":"Your note spends five bullet points saying the patient is stable: vitals stable, exam stable, labs stable, no events, no complaints. It's five ways to say one thing.","task":"Collapse the five points into one sentence.","tips":["Five 'stables' compress to one: stable overnight, no events.","Bullets should carry distinct facts, not variations on one.","Compression is a courtesy to the next reader."],"focus":["concision","clarity"],"placeholder":"Stable overnight — no events, no new complaints."},
    {"id":"concise-doc-early-13","level":"early","profession":"doctor","title":"The over-qualified referral","scenario":"Your referral question is wrapped in so many qualifiers — \"if you think it's appropriate and if it's not too much trouble and if you have time\" — that the actual ask is hard to find.","task":"Rewrite the question directly, cutting the qualifier chain.","tips":["Qualifiers meant to be polite just bury the ask.","One clean question is more respectful than a hedged one.","'Could you see her this week?' — that's the whole ask."],"focus":["concision","clarity"]},
    {"id":"concise-doc-early-14","level":"early","profession":"doctor","title":"The wordy nursing note","scenario":"Your instruction to nursing reads: \"Please be advised that it would be preferable if the patient were to be encouraged to ambulate at regular intervals throughout the course of the day.\" It's a walking order buried in formality.","task":"Rewrite it as a plain, short instruction.","tips":["'Please be advised that it would be preferable if' — all deletable.","The order is: help him walk a few times a day.","Formality here is friction, not respect."],"focus":["concision","clarity"],"placeholder":"Help him walk three times today."},
    {"id":"concise-doc-early-15","level":"early","profession":"doctor","title":"The presentation that won't end","scenario":"You've made your point on rounds but keep adding \"and also,\" \"one more thing,\" and \"just to add.\" The attending has already nodded and moved on mentally.","task":"Write a clean two-sentence version that stops when the point is made.","tips":["Make the point, add one support, stop.","'Just to add' usually adds nothing — resist it.","Knowing when to stop is a skill; practice the full stop."],"focus":["concision","impact"]},
    {"id":"concise-doc-early-16","level":"early","profession":"doctor","title":"The passive-voice fog","scenario":"Your note says: \"It was felt that the medication should be held and that consideration would be given to restarting it at a later time.\" Nobody knows who decided what.","task":"Rewrite in active voice naming the decision and the plan.","tips":["'It was felt' hides the decider — say 'we held it'.","Active voice is shorter and assigns responsibility.","Passive fog is where accountability goes to hide."],"focus":["concision","precision"]},
    {"id":"concise-doc-early-17","level":"early","profession":"doctor","title":"The bloated text to a colleague","scenario":"You're texting a co-resident to cover a patient for ten minutes. Your text is a full paragraph of context for a tiny favor.","task":"Cut it to one line: the ask and the timeframe.","tips":["Small favor, small message — match the scale.","'Can you eyeball bed 5 for ten min? Stepping out.'","Over-explaining a small ask makes it feel bigger."],"focus":["concision","clarity"]},
    {"id":"concise-doc-early-18","level":"early","profession":"doctor","title":"The redundant reassurance","scenario":"Reassuring a patient, you say the same comforting thing four different ways, and by the fourth it starts to sound like you're worried too.","task":"Rewrite as one clear, warm sentence of reassurance.","tips":["Say it once, mean it, stop — repetition reads as anxiety.","One honest sentence lands harder than four soft ones.","Trust the patient to hear you the first time."],"focus":["concision","audience"]},
    {"id":"concise-doc-early-19","level":"early","profession":"doctor","title":"The over-caveated consult reply","scenario":"You're answering a junior's consult question, but you bury your actual recommendation under six caveats about what you can't be sure of without more information.","task":"Give the recommendation first, then the single most important caveat.","tips":["Lead with your best read; caveats come after, and just one.","Six caveats read as no answer at all.","The junior needs a direction, not a disclaimer."],"focus":["concision","clarity"]},
    {"id":"concise-doc-early-20","level":"early","profession":"doctor","title":"The intro that repeats the label","scenario":"Every slide of your case presentation starts with \"As I mentioned earlier\" or \"As you can see here.\" The room can see; you don't need to narrate it.","task":"Rewrite two transitions to carry content instead of narration.","tips":["'As you can see' — cut it, just state what's there.","Narration of the obvious wastes the audience's attention.","Let the transition advance the story, not describe the slide."],"focus":["concision","impact"]},
    {"id":"concise-doc-early-21","level":"early","profession":"doctor","title":"The overnight event, trimmed","scenario":"At rounds you describe an overnight fever in a full minute of buildup — the timeline, what you thought, what you ruled out — before the two facts that matter.","task":"State the event in two sentences: what happened and what you did.","tips":["Fever, cultures drawn, antibiotics started — that's it.","Your reasoning is available on request; lead with the facts.","The team can drill down; don't pre-empt them with the full story."],"focus":["concision","structure"],"placeholder":"He spiked to 38.9 overnight — cultures drawn, antibiotics started."},
    {"id":"concise-doc-early-22","level":"early","profession":"doctor","title":"The verbose portal reply","scenario":"A patient asked a one-line question in the portal. Your reply is five paragraphs covering every related topic they didn't ask about.","task":"Cut the reply to answer only what was asked, in two or three sentences.","tips":["Answer the question; resist the urge to teach the whole topic.","Extra topics feel generous but read as overwhelming.","If they want more, they'll ask — leave the door open, briefly."],"focus":["concision","audience"]},
    {"id":"concise-doc-early-23","level":"early","profession":"doctor","title":"The bloated goals-of-care note","scenario":"Your note documenting a family meeting runs three dense paragraphs. The next reader needs to know what was decided in one line.","task":"Write the one-line summary that leads the note, then note what the detail supports.","tips":["Lead with the decision: comfort-focused care, family in agreement.","The paragraph of context supports the line; it doesn't replace it.","The next reader in a crisis needs the headline, fast."],"focus":["concision","clarity"]},
    {"id":"concise-doc-early-24","level":"early","profession":"doctor","title":"The over-softened correction","scenario":"You need to tell a nurse a dose was charted wrong. Your message is so cushioned in softeners that it's unclear there's an actual error to fix.","task":"Rewrite it clearly and kindly in two sentences — the fact, then the fix.","tips":["State the error plainly; kindness is in the tone, not the vagueness.","Over-softening risks the correction being missed entirely.","Clear is kind: the fix has to be unmistakable."],"focus":["concision","clarity"]},
    {"id":"concise-doc-early-25","level":"early","profession":"doctor","title":"The handoff that could be a bitset","scenario":"Your written handoff repeats standard information for every patient — same allergies phrasing, same code status boilerplate — instead of flagging only what differs.","task":"Rewrite two entries to show only what's non-standard, and say the rest is default.","tips":["Flag the exceptions; assume the defaults.","'Full code, no allergies' is one tag, not two sentences.","The reader scans for what's different — make that easy."],"focus":["concision","precision"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-doc-early-01","level":"early","profession":"doctor","title":"'A little' won't do","scenario":"You tell the attending the patient's urine output is \"a little low\" and his fever \"came down some.\" She asks for the actual numbers, which you have.","task":"Rewrite the report replacing the vague words with the specific figures.","tips":["'A little low' becomes '20 mL an hour, down from 60'.","Numbers let the listener judge; adjectives make them ask.","You have the data — put it in the sentence."],"focus":["precision","clarity"],"placeholder":"Urine output dropped to 20 mL an hour, down from 60 this morning."},
    {"id":"precision-doc-early-02","level":"early","profession":"doctor","title":"The trend, not the snapshot","scenario":"You report a single blood-pressure reading. The attending can't tell if it's improving or worsening because you gave a number without its trajectory.","task":"Rewrite the report to show the value AND the trend over the shift.","tips":["A number alone is a dot; give the line it's on.","'90, down from 120 three hours ago' tells the story.","Trend answers the question the snapshot raises."],"focus":["precision","impact"]},
    {"id":"precision-doc-early-03","level":"early","profession":"doctor","title":"So what, now what","scenario":"You present a potassium of 5.9 and stop. The attending waits: what does it mean, and what are you doing about it? You presented the data without the insight or the action.","task":"Rewrite as What, So What, Now What in three sentences.","tips":["What: the value. So What: it's high enough to affect the heart.","Now What: the specific step you're taking or recommending.","Data without 'so what' is trivia; add the interpretation."],"focus":["precision","structure"],"placeholder":"Potassium is 5.9 — high enough to worry about his heart. I've —"},
    {"id":"precision-doc-early-04","level":"early","profession":"doctor","title":"The skeptic's follow-up","scenario":"You tell the family the patient is \"doing much better.\" A skeptical relative asks, \"Better how? Compared to what?\" You have concrete answers but led with the vague claim.","task":"Rewrite the update with the specific, observable evidence for 'better'.","tips":["Anchor 'better' to something they can see: off oxygen, eating, walking.","Compared to when — name the baseline.","Pass the skeptic test: would your claim survive 'prove it'?"],"focus":["precision","audience"]},
    {"id":"precision-doc-early-05","level":"early","profession":"doctor","title":"Dates, not 'recently'","scenario":"Your note says the patient's symptoms started \"recently\" and the medication was changed \"a while ago.\" The consultant needs the actual timeline to reason about causation.","task":"Rewrite the two phrases with specific timeframes.","tips":["'Recently' means nothing to a reader — give the day or day-count.","Timing is often the diagnostic clue; don't blur it.","'Three days ago' beats 'recently' every time."],"focus":["precision","clarity"]},
    {"id":"precision-doc-early-06","level":"early","profession":"doctor","title":"Quantify the pain","scenario":"You chart that the patient's pain is \"better\" after medication. The next team can't tell if that's 8-to-6 or 8-to-2, which changes the plan.","task":"Rewrite using the pain scale, before and after.","tips":["'Better' spans everything from trivial to dramatic — pin it.","Before-and-after on the same scale shows the effect size.","Precision here changes the next dosing decision."],"focus":["precision","clarity"],"placeholder":"Pain down from 8 to 3 out of 10 after the morphine."},
    {"id":"precision-doc-early-07","level":"early","profession":"doctor","title":"The evidence for the diagnosis","scenario":"You state a working diagnosis to the attending but don't cite what supports it. She asks, \"What makes you say pneumonia?\" You have three findings but led with the label.","task":"Rewrite to state the diagnosis and the three findings that support it.","tips":["A diagnosis is a claim; name the evidence beneath it.","Three concrete findings beat one confident assertion.","This is the skeptic test in clinical form."],"focus":["precision","structure"]},
    {"id":"precision-doc-early-08","level":"early","profession":"doctor","title":"'Stable' means what, exactly","scenario":"You sign out that the patient is \"stable,\" but the covering doctor doesn't know your baseline, so the word is uninformative. You know the specific parameters.","task":"Rewrite 'stable' into two or three specific, current values.","tips":["'Stable' is a summary word — back it with the numbers you mean.","Give the covering doctor the baseline to compare against.","Vague reassurance fails the moment something changes."],"focus":["precision","clarity"]},
    {"id":"precision-doc-early-09","level":"early","profession":"doctor","title":"The insight from the lab panel","scenario":"You read out fifteen lab values on rounds, all of them. The attending's eyes glaze; she wants the one or two that carry an insight, not the recital.","task":"Pick the two meaningful results and state what each tells you, skipping the rest.","tips":["Data becomes evidence only when tied to a conclusion.","Read the two that changed the plan; note the rest as normal.","Fifteen numbers is data dumping; two with meaning is a read."],"focus":["precision","concision"]},
    {"id":"precision-doc-early-10","level":"early","profession":"doctor","title":"The dose, exactly","scenario":"You tell the nurse to give \"a bit more\" of the pain medication. She needs an exact dose to chart and administer safely.","task":"Restate the order with the precise drug, dose, and route.","tips":["'A bit more' is not an order — it's a hazard.","Exact number, exact route, exact timing.","Precision in dosing is a patient-safety issue, not pedantry."],"focus":["precision","clarity"],"placeholder":"Give an additional 2 mg of morphine, IV, now."},
    {"id":"precision-doc-early-11","level":"early","profession":"doctor","title":"The vague risk","scenario":"You tell a patient a procedure has \"a small risk\" of bleeding. He asks what small means. You know the rough figure but hid behind the adjective.","task":"Rewrite the risk statement with a concrete, honest sense of the number.","tips":["'Small' means different things to different people — give a rough number.","Honesty about magnitude builds trust, not fear.","A number he can hold beats a word he has to interpret."],"focus":["precision","audience"]},
    {"id":"precision-doc-early-12","level":"early","profession":"doctor","title":"The measurable goal","scenario":"Your plan says you'll \"optimize\" the patient's blood sugar before discharge. The team can't tell when that goal is met because there's no target.","task":"Rewrite the goal with a specific target and timeframe.","tips":["'Optimize' is a direction, not a destination — set the number.","A target lets everyone know when you're done.","'Under 180 before meals by Thursday' is a goal you can hit."],"focus":["precision","structure"]},
    {"id":"precision-doc-early-13","level":"early","profession":"doctor","title":"The evidence behind the reassurance","scenario":"You reassure the family that the scan is \"nothing to worry about,\" but you don't give them the finding that justifies your confidence. They want the basis, not just the verdict.","task":"Rewrite to pair the reassurance with the specific reason for it.","tips":["Confidence lands better when you show your reasoning.","Name the reassuring finding in plain words.","'Nothing to worry about, because...' beats the bare verdict."],"focus":["precision","audience"]},
    {"id":"precision-doc-early-14","level":"early","profession":"doctor","title":"The response rate, specified","scenario":"You tell the attending the patient's fever \"responded to antibiotics.\" She asks how much and how fast. You have the temperature curve but gave a summary word.","task":"Rewrite with the specific temperature change and timeframe.","tips":["'Responded' hides the size and speed of the response.","Give the before, the after, and the hours between.","The specifics tell her whether the antibiotic is working or coincidental."],"focus":["precision","clarity"]},
    {"id":"precision-doc-early-15","level":"early","profession":"doctor","title":"The imprecise handoff time","scenario":"You sign out that the patient \"should be reassessed later\" for his breathing. The covering doctor doesn't know when 'later' is, so it may not happen.","task":"Rewrite with a specific reassessment time and the trigger.","tips":["'Later' becomes 'in two hours' or 'by 10 p.m.'","Attach the trigger: reassess sooner if X.","An unscheduled task is an undone task."],"focus":["precision","structure"],"placeholder":"Recheck his breathing at 10 p.m. — sooner if oxygen needs climb."},
    {"id":"precision-doc-early-16","level":"early","profession":"doctor","title":"The number that needs context","scenario":"You report a white blood cell count of 14 to the family, who have no reference point. The number alarms them without the context that it's mildly elevated and expected.","task":"Rewrite to give the number its meaning in plain terms.","tips":["A raw number without a reference range scares laypeople.","Say whether it's a little high, a lot high, or expected.","Precision includes interpretation, not just the figure."],"focus":["precision","audience"]},
    {"id":"precision-doc-early-17","level":"early","profession":"doctor","title":"The follow-up, dated","scenario":"Your discharge plan says to \"follow up with your doctor soon.\" The patient doesn't know if that's tomorrow or next month, so it slips.","task":"Rewrite with a specific window and who to call.","tips":["'Soon' is where follow-ups go to die.","Give the window: within one week, and the clinic number.","Specificity turns intention into a scheduled action."],"focus":["precision","clarity"]},
    {"id":"precision-doc-early-18","level":"early","profession":"doctor","title":"The improvement, evidenced","scenario":"You tell the attending the patient is \"trending in the right direction.\" She wants the two data points that show the trend, not the metaphor.","task":"Rewrite naming the two specific measures and their movement.","tips":["A trend needs at least two points — name them.","'Right direction' is a feeling; the numbers are the proof.","Pass the skeptic test with data, not optimism."],"focus":["precision","impact"]},
    {"id":"precision-doc-early-19","level":"early","profession":"doctor","title":"The exact allergy","scenario":"You note the patient has an \"allergy to some antibiotics.\" The next prescriber can't tell which, or what the reaction was, so they either over-avoid or risk harm.","task":"Rewrite with the specific drug and the specific reaction.","tips":["'Some antibiotics' is dangerous vagueness — name the drug.","The reaction matters: a rash is not anaphylaxis.","Precision here prevents both harm and over-caution."],"focus":["precision","clarity"]},
    {"id":"precision-doc-early-20","level":"early","profession":"doctor","title":"The volume, measured","scenario":"You tell the team the patient \"drank a decent amount\" of fluid overnight. For someone on fluid restriction, 'decent' isn't good enough.","task":"Rewrite with the measured intake and how it compares to the limit.","tips":["'A decent amount' is unusable for a fluid-restricted patient.","Give the milliliters and the target.","Precision in intake and output is the whole point of tracking it."],"focus":["precision","clarity"],"placeholder":"He took 900 mL overnight — 300 under his 1200 mL limit."},
    {"id":"precision-doc-early-21","level":"early","profession":"doctor","title":"The evidence for the escalation","scenario":"You escalate to your senior saying the patient \"doesn't look good.\" She needs the specific findings that prompted your worry, not the gestalt.","task":"Rewrite the escalation with the two or three objective findings.","tips":["'Doesn't look good' is your instinct; name what triggered it.","Objective findings let her judge urgency remotely.","Trust your gestalt, but hand her the evidence too."],"focus":["precision","clarity"]},
    {"id":"precision-doc-early-22","level":"early","profession":"doctor","title":"The rate of change","scenario":"You mention the patient's kidney numbers are \"getting worse.\" Whether that's over hours or days completely changes the urgency, and you left it out.","task":"Rewrite with the values and the time interval between them.","tips":["Rate of change, not just direction, drives the response.","Give both values and the hours or days between.","A slow drift and a rapid crash need different actions."],"focus":["precision","impact"]},
    {"id":"precision-doc-early-23","level":"early","profession":"doctor","title":"The specific instruction to nursing","scenario":"You ask the nurse to \"watch his blood pressure closely.\" She doesn't know how often or what number should trigger a call.","task":"Rewrite with the check frequency and the exact call threshold.","tips":["'Closely' means different things to different nurses — specify.","Give the interval and the number that triggers a page.","A precise watch order is one she can actually execute."],"focus":["precision","clarity"],"placeholder":"Check his pressure every 30 minutes — call me if the top number drops below 90."},
    {"id":"precision-doc-early-24","level":"early","profession":"doctor","title":"The insight, not the printout","scenario":"You paste an entire trend of vital signs into your note. The next reader has to do the interpretation you should have done, extracting the one signal from the noise.","task":"Write the one-sentence insight the trend supports, and cite the key numbers.","tips":["Do the reader's work: state what the trend shows.","Cite two supporting numbers, not the whole printout.","An insight is a claim plus its evidence, compressed."],"focus":["precision","concision"]},
    {"id":"precision-doc-early-25","level":"early","profession":"doctor","title":"The honest degree of certainty","scenario":"You tell the attending you're \"pretty sure\" it's a viral illness. She wants to know how sure, and what would change your mind. You gave a vague confidence level.","task":"Rewrite stating your working diagnosis, roughly how confident, and the one finding that would change it.","tips":["Calibrate: 'most likely viral' is different from 'certain'.","Name the finding that would shift you — that's real reasoning.","Precision about uncertainty is a skill, not a weakness."],"focus":["precision","structure"]}
  ],
  "executive-presence": [
    {"id":"presence-doc-early-01","level":"early","profession":"doctor","title":"Recommend, don't present a menu","scenario":"On rounds you lay out three options for the patient's antibiotics and stop, waiting for the attending to choose. She says, \"What do YOU think we should do?\"","task":"Rewrite to lead with your recommendation and name it as yours.","tips":["Give your pick first, then the reasoning — not a neutral menu.","'I'd start X' shows you've done the thinking.","Options without a recommendation push the work back to her."],"focus":["impact","structure"],"placeholder":"I'd start the narrow antibiotic. Here's why over the alternatives:"},
    {"id":"presence-doc-early-02","level":"early","profession":"doctor","title":"Fact versus judgment","scenario":"Your presentation blends observations and interpretations without separating them: \"His pressure is low and he's clearly septic and we need pressors.\" The attending can't tell what you saw from what you concluded.","task":"Rewrite separating the facts from your judgment, each labeled.","tips":["State what you observed, then what you make of it.","'Pressure is 85; I read that as early sepsis' keeps them distinct.","Blending the two hides where your reasoning could be wrong."],"focus":["precision","clarity"]},
    {"id":"presence-doc-early-03","level":"early","profession":"doctor","title":"Signpost the presentation","scenario":"You launch into a complex patient with no map, and the attending can't tell how many problems are coming or how they relate. She keeps interrupting to orient herself.","task":"Write the one-sentence signpost that opens your presentation.","tips":["Tell them the shape: 'three active problems, one urgent'.","A signpost lets the listener allocate attention.","Structure stated up front reads as command of the case."],"focus":["structure","impact"],"placeholder":"Three active problems today — I'll start with the one that's urgent."},
    {"id":"presence-doc-early-04","level":"early","profession":"doctor","title":"Owning the plan in the family meeting","scenario":"In a family meeting you present options so neutrally that the family, overwhelmed, asks, \"But what would you do?\" You'd been avoiding steering them.","task":"Write a 2-3 sentence recommendation that guides while respecting their choice.","tips":["Families often want your honest guidance, not just a menu.","'If she were my mother, I'd...' owns it without overriding them.","Neutrality can read as abandonment when they're scared."],"focus":["impact","audience"]},
    {"id":"presence-doc-early-05","level":"early","profession":"doctor","title":"The confident 'I don't know yet'","scenario":"The attending asks a question you can't answer. You mumble and look away, undermining everything else you said. A composed 'I don't know, but here's how I'll find out' would land better.","task":"Write a composed response that admits the gap and states your next step.","tips":["'I don't know' with a plan reads as confidence, not weakness.","Name how you'll get the answer and by when.","Presence is steady under not-knowing, not pretending to know."],"focus":["impact","clarity"],"placeholder":"I don't know yet — I'll check the culture results and get back to you by noon."},
    {"id":"presence-doc-early-06","level":"early","profession":"doctor","title":"The recommendation to the consultant","scenario":"You're calling a consultant. Instead of asking a clear question with your leaning, you present the case flatly and wait. The consultant asks what you actually think.","task":"Rewrite to include your working assessment and what you're leaning toward.","tips":["Show your thinking, then ask — consultants respect a point of view.","'I think it's X and I'm leaning toward Y — do you agree?'","A stance invites collaboration; a blank slate invites work."],"focus":["impact","clarity"]},
    {"id":"presence-doc-early-07","level":"early","profession":"doctor","title":"Standing behind the discharge call","scenario":"You believe the patient is ready to go home, but you present it so tentatively — \"maybe we could possibly consider discharge?\" — that the attending doubts it.","task":"Rewrite as a confident recommendation with the reasoning that backs it.","tips":["State the recommendation plainly: he's ready for discharge.","Back it with the two criteria he's met.","Tentative phrasing invites the pushback your reasoning should prevent."],"focus":["impact","precision"],"placeholder":"He's ready for discharge today — he's met both criteria we set:"},
    {"id":"presence-doc-early-08","level":"early","profession":"doctor","title":"Composure when challenged","scenario":"An attending questions your plan sharply in front of the team. You feel defensive and your voice rises. A composed response would defend the reasoning without defending your ego.","task":"Write a calm 2-sentence response that engages the substance of the challenge.","tips":["Address the reasoning, not the tone of the challenge.","'That's fair — here's what led me there' stays composed.","Presence is separating the critique of the plan from a critique of you."],"focus":["impact","clarity"]},
    {"id":"presence-doc-early-09","level":"early","profession":"doctor","title":"Leading the code debrief","scenario":"After a resuscitation, the team looks to you to summarize what happened and what's next. You ramble. A crisp, confident summary would steady the room.","task":"Write a 3-sentence summary: what happened, current status, next step.","tips":["The team needs a steady voice, not a perfect one.","Three clean sentences project control of the situation.","Signpost the next step so people know what to do."],"focus":["impact","structure"]},
    {"id":"presence-doc-early-10","level":"early","profession":"doctor","title":"The judgment call, owned","scenario":"You made a judgment call overnight that the attending questions. Instead of owning your reasoning, you say \"the nurse suggested it\" and deflect. Presence means standing behind your decision.","task":"Rewrite to own the decision and the reasoning, without deflecting.","tips":["'I decided to X because Y' — own it, right or wrong.","Deflection reads worse than a defensible judgment call.","You can own a decision and still be open to a better one."],"focus":["impact","clarity"]},
    {"id":"presence-doc-early-11","level":"early","profession":"doctor","title":"The recommendation email to the team","scenario":"You email the team about a workflow problem but only describe it, ending with 'thoughts?' — pushing the solution to everyone else. A junior with presence proposes something.","task":"Rewrite to name the problem and propose a specific fix.","tips":["Describe-then-propose: end with your recommendation, not a question.","'Thoughts?' abdicates; 'I suggest X' contributes.","Even a wrong proposal moves the conversation forward."],"focus":["impact","structure"]},
    {"id":"presence-doc-early-12","level":"early","profession":"doctor","title":"The steady bedside voice","scenario":"A patient is anxious and reading your face. Your uncertain phrasing and darting eyes amplify their fear. A calm, grounded manner would settle them even without new information.","task":"Write a 2-sentence bedside statement that projects steadiness.","tips":["Slow, plain sentences read as control to an anxious patient.","You don't need answers to project that you're on it.","Presence at the bedside is as much manner as content."],"focus":["impact","audience"]},
    {"id":"presence-doc-early-13","level":"early","profession":"doctor","title":"The clear recommendation under time pressure","scenario":"The attending has thirty seconds between patients and asks your read. You waffle. Presence is delivering a crisp recommendation even when you're not fully certain.","task":"Write a 2-sentence recommendation with the one caveat, no waffling.","tips":["Commit to a recommendation; add one honest caveat.","Thirty seconds rewards decisiveness, not exhaustive hedging.","'I'd do X, though I'd watch for Y' is confident and honest."],"focus":["impact","concision"]},
    {"id":"presence-doc-early-14","level":"early","profession":"doctor","title":"Presenting to the whole team","scenario":"At a multidisciplinary meeting with nursing, pharmacy, and social work, you speak only to the attending and mumble the rest. Presence is addressing the whole room with a clear plan.","task":"Write an opening that addresses the full team and names the shared goal.","tips":["Speak to the room, not just the senior in it.","Name the goal everyone's working toward: 'get him home safely by Friday'.","Presence is inclusive command, not a private conversation overheard."],"focus":["impact","audience"]},
    {"id":"presence-doc-early-15","level":"early","profession":"doctor","title":"The recommendation with a stance on risk","scenario":"You lay out a risky and a cautious option evenly, hiding your own read. The attending wants to know which risk you'd accept and why. Presence is taking a position on the tradeoff.","task":"Rewrite to state which option you'd choose and the risk you're willing to accept.","tips":["Name the tradeoff and where you'd land on it.","'I'd accept the small bleed risk to avoid the clot' is a stance.","Neutral risk presentation ducks the actual decision."],"focus":["impact","precision"]},
    {"id":"presence-doc-early-16","level":"early","profession":"doctor","title":"The fact-judgment split for the family","scenario":"Telling a family about a scan, you fuse the finding with your interpretation so tightly that they can't tell what's certain from what's your read. Separating them builds trust.","task":"Rewrite separating what the scan shows from what you think it means.","tips":["'The scan shows X; what I think that means is Y.'","Families trust you more when you're clear about the line.","Fused fact-and-judgment sounds authoritative but hides uncertainty."],"focus":["clarity","audience"]},
    {"id":"presence-doc-early-17","level":"early","profession":"doctor","title":"Owning the uncertainty out loud","scenario":"You're genuinely unsure of the diagnosis. Instead of naming the uncertainty confidently and giving a plan, you go quiet and hope no one asks. Presence is owning ambiguity with a path.","task":"Write a 2-3 sentence statement that names the uncertainty and the plan to resolve it.","tips":["'We're not sure yet — here's what we're doing to find out' is strong.","Owning uncertainty beats projecting false confidence.","A named plan turns 'I don't know' into leadership."],"focus":["impact","structure"]},
    {"id":"presence-doc-early-18","level":"early","profession":"doctor","title":"The junior who defers everything","scenario":"You preface every statement with \"I could be wrong, but\" and \"this is probably a dumb question.\" The self-deprecation undercuts your real contributions. Presence is contributing without apologizing for it.","task":"Rewrite two of these hedged openings to state the point directly.","tips":["Cut 'this is probably dumb' — ask the question straight.","Reflexive self-deprecation trains the room to discount you.","You can be humble in substance without hedging every sentence."],"focus":["impact","concision"]},
    {"id":"presence-doc-early-19","level":"early","profession":"doctor","title":"The recommendation to keep or stop treatment","scenario":"The team debates continuing an antibiotic. You have a view but present both sides evenly to avoid conflict. Presence is stating your recommendation and holding it under scrutiny.","task":"Write your recommendation and the single strongest reason for it.","tips":["Pick a side; the reasoning is your defense, not neutrality.","One strong reason beats a balanced summary.","Avoiding a stance to avoid conflict just defers the decision."],"focus":["impact","clarity"]},
    {"id":"presence-doc-early-20","level":"early","profession":"doctor","title":"Composed correction of a senior","scenario":"You notice the attending is about to order a medication the patient is allergic to. You need to speak up firmly and calmly, without either freezing or blurting it aggressively.","task":"Write a calm, direct 1-2 sentence interjection that flags the allergy.","tips":["Direct and respectful: 'Before we do — she's allergic to that.'","Presence is speaking up steadily on a safety issue.","Neither freeze nor accuse; just state the fact clearly."],"focus":["impact","clarity"],"placeholder":"Before we order that — she's listed as allergic to it."},
    {"id":"presence-doc-early-21","level":"early","profession":"doctor","title":"The plan, delivered not floated","scenario":"You end your presentation with the plan phrased as a question — \"so maybe we do X?\" — inviting the attending to redo your work. Presence is proposing the plan and inviting correction, not authorship.","task":"Rewrite the plan as a proposal the attending can approve or amend.","tips":["State the plan; invite amendment, not authorship.","'My plan is X — I'd welcome your thoughts' owns it.","A floated question makes the attending do the planning."],"focus":["impact","structure"]},
    {"id":"presence-doc-early-22","level":"early","profession":"doctor","title":"The steady handoff of a crashing patient","scenario":"You're handing off a rapidly deteriorating patient to the next team. Your panic leaks into a scattered report. Presence is a calm, structured handoff that steadies the receiving team.","task":"Write a composed 3-sentence handoff: situation, your read, what you need them to do.","tips":["Calm structure counteracts the chaos of a crashing patient.","Your read plus a clear ask focuses the receiving team.","Presence under pressure is what a scared team looks to."],"focus":["impact","structure"]},
    {"id":"presence-doc-early-23","level":"early","profession":"doctor","title":"Naming your recommendation to the patient","scenario":"You explain two treatment paths to the patient neutrally, then wait. The patient, unequipped to choose alone, wants your professional recommendation. Presence is giving it while preserving their autonomy.","task":"Write a 2-sentence recommendation that guides the patient and leaves the choice theirs.","tips":["'My recommendation is X, but this is your decision' does both.","Patients usually want your honest lean, not just facts.","A recommendation is guidance, not coercion."],"focus":["impact","audience"]},
    {"id":"presence-doc-early-24","level":"early","profession":"doctor","title":"The confident summary at sign-out","scenario":"You end each sign-out trailing off, unsure you've covered everything, undermining the receiving doctor's confidence. Presence is a crisp close that signals you've handed off cleanly.","task":"Write a two-sentence closing summary that projects a clean, complete handoff.","tips":["Close with the one watcher and the one thing to do.","A confident close reassures the receiving doctor.","Trailing off invites doubt about what you might have missed."],"focus":["impact","concision"]},
    {"id":"presence-doc-early-25","level":"early","profession":"doctor","title":"Standing behind a call in morbidity review","scenario":"In a case review, your overnight decision is scrutinized. You have a choice: defend it defensively, cave entirely, or explain your reasoning with composure and openness to learning. Presence is the third.","task":"Write a 3-sentence response that owns the decision, explains the reasoning, and stays open to the lesson.","tips":["Own the call and the reasoning you had at the time.","Openness to the lesson is strength, not surrender.","Presence is defending your process without defending your ego."],"focus":["impact","clarity"]}
  ],
  "answering-under-pressure": [
    {"id":"pressure-doc-early-01","level":"early","profession":"doctor","title":"Answer the question asked","scenario":"On rounds the attending asks, \"Is he safe to discharge today?\" You launch into the lab trends and history. She repeats: \"Yes or no?\"","task":"Answer the yes/no first, then give the one reason.","tips":["Lead with the direct answer: yes, or no.","The reasoning comes after the answer, not instead of it.","Answering around the question reads as not having one."],"focus":["clarity","impact"],"placeholder":"Yes — he's safe to discharge, because he's met both criteria we set."},
    {"id":"pressure-doc-early-02","level":"early","profession":"doctor","title":"The 'why didn't you' challenge","scenario":"An attending asks, sharply, \"Why didn't you order the scan last night?\" You feel accused and start justifying defensively. A specific, non-defensive answer would serve better.","task":"Write a 2-sentence answer that gives the actual reasoning, without defensiveness.","tips":["Answer with your reasoning at the time, calmly.","'I held off because X; in hindsight Y' is honest, not defensive.","The question is about the decision, not about you."],"focus":["clarity","impact"]},
    {"id":"pressure-doc-early-03","level":"early","profession":"doctor","title":"The honest 'I don't know' with a path","scenario":"A family member asks how long recovery will take. You genuinely don't know. You're tempted to guess or dodge. The strong move is an honest not-knowing with a path to the answer.","task":"Write a 2-sentence response that admits the uncertainty and gives a next step.","tips":["'I can't say precisely, but here's what we'll know and when.'","A guess you can't back damages trust more than 'I don't know'.","Pair uncertainty with a concrete path to reduce it."],"focus":["clarity","audience"],"placeholder":"I can't give you an exact timeline yet — but after tomorrow's tests we'll know more."},
    {"id":"pressure-doc-early-04","level":"early","profession":"doctor","title":"Pushback from the family","scenario":"A family member insists their relative needs a test you don't think is warranted, and pushes hard. You get flustered. A calm answer with specifics beats capitulating or getting defensive.","task":"Write a 2-3 sentence response that addresses their concern with specifics.","tips":["Acknowledge the worry, then explain with a concrete reason.","Specifics defuse pressure better than authority.","You can hold the line and validate the fear at once."],"focus":["clarity","audience"]},
    {"id":"pressure-doc-early-05","level":"early","profession":"doctor","title":"The consultant's tough question","scenario":"You call a consultant who immediately asks, \"What have you already ruled out?\" You didn't expect it and ramble. A crisp answer to exactly what's asked would establish credibility.","task":"Write a direct 2-sentence answer to the question asked.","tips":["Answer the specific question, not the whole case.","'We've ruled out X and Y; still open is Z.'","Answering precisely under pressure builds the consultant's trust."],"focus":["clarity","concision"]},
    {"id":"pressure-doc-early-06","level":"early","profession":"doctor","title":"The patient's direct fear","scenario":"A patient asks, point-blank, \"Am I dying?\" You want to soften and deflect, but they asked directly and deserve a direct, humane answer.","task":"Write a 2-3 sentence response that answers honestly and stays present.","tips":["Meet the question — evasion reads as the worst answer.","Honest and gentle can coexist; don't hide behind vagueness.","Stay with them after the answer; don't retreat into logistics."],"focus":["clarity","audience"]},
    {"id":"pressure-doc-early-07","level":"early","profession":"doctor","title":"When you got it wrong","scenario":"The attending points out your diagnosis was off. Your instinct is to defend it. The stronger response acknowledges the miss and states what you'd do differently.","task":"Write a 2-sentence response that owns the error and names the correction.","tips":["Acknowledge cleanly; don't relitigate the losing case.","'You're right — I missed X. I'd now do Y.'","Owning a miss under pressure reads as maturity."],"focus":["clarity","impact"]},
    {"id":"pressure-doc-early-08","level":"early","profession":"doctor","title":"The rapid-fire pimping","scenario":"On rounds the attending fires three quick questions. You know two answers but freeze on the third. Composure is answering what you know and flagging what you don't, without spiraling.","task":"Write responses that answer the two you know and handle the third with 'I don't know, I'll look it up'.","tips":["Answer what you know crisply; don't let the gap erase the wins.","'I'm not sure — I'll look it up and tell you at noon.'","A frozen silence is worse than an honest gap."],"focus":["clarity","concision"]},
    {"id":"pressure-doc-early-09","level":"early","profession":"doctor","title":"The angry family, the real question","scenario":"A furious family member launches a long complaint about wait times, but buried in it is a real question: is their relative getting worse? You need to find and answer the actual question under the anger.","task":"Write a response that acknowledges the frustration and answers the underlying question.","tips":["Hear the anger, then answer the question inside it.","'I hear you're frustrated — and no, she's not getting worse.'","The emotion and the question both need addressing."],"focus":["audience","clarity"]},
    {"id":"pressure-doc-early-10","level":"early","profession":"doctor","title":"The nurse's challenge to your order","scenario":"A nurse questions your order: \"Are you sure about that dose?\" You feel challenged. The right move is to treat it as the safety check it is and answer clearly.","task":"Write a 2-sentence response that welcomes the check and confirms or corrects.","tips":["Treat the question as a safety catch, not a challenge.","'Good catch to double-check — yes, that's right because X.'","Defensiveness toward a nurse's question is a safety risk."],"focus":["clarity","impact"]},
    {"id":"pressure-doc-early-11","level":"early","profession":"doctor","title":"The question you'd rather avoid","scenario":"A patient asks whether the delay in diagnosis harmed them. It's an uncomfortable question you'd rather sidestep. Answering it directly and honestly is the professional move.","task":"Write a 2-3 sentence honest response that doesn't dodge.","tips":["Don't sidestep a direct question about their care.","Honest and careful; state what you know and don't.","Dodging reads as hiding something, even when you aren't."],"focus":["clarity","audience"]},
    {"id":"pressure-doc-early-12","level":"early","profession":"doctor","title":"The attending disagrees with your plan","scenario":"You present a plan and the attending disagrees. You can cave immediately or defend your reasoning first. The strong move is to answer the disagreement with your rationale before adjusting.","task":"Write a 2-sentence response that defends your reasoning, then stays open.","tips":["State why you chose it before folding.","'My thinking was X — but I hear your concern about Y.'","Caving instantly teaches the attending you had no reasoning."],"focus":["clarity","impact"]},
    {"id":"pressure-doc-early-13","level":"early","profession":"doctor","title":"The public mistake in front of the patient","scenario":"You misspeak in front of a patient, and the attending corrects you. You feel embarrassed. Recovering composure and answering cleanly matters more than the flush of embarrassment.","task":"Write a composed 1-2 sentence recovery directed to the patient.","tips":["Correct it plainly to the patient; don't spiral.","'Let me correct that — the plan is actually X.'","A calm recovery reassures the patient more than perfection would."],"focus":["clarity","audience"]},
    {"id":"pressure-doc-early-14","level":"early","profession":"doctor","title":"The 'what would you do' from the patient","scenario":"A patient facing a decision asks, \"What would you do if it were you?\" You're tempted to deflect to 'it's your choice.' The honest answer, framed as guidance, is what they need.","task":"Write a 2-sentence response that gives your honest lean and preserves their choice.","tips":["Answer the actual question — they want your judgment.","'If it were me, I'd lean toward X, but this is your call.'","Deflecting entirely can feel like abandonment."],"focus":["clarity","audience"]},
    {"id":"pressure-doc-early-15","level":"early","profession":"doctor","title":"The specifics that beat defensiveness","scenario":"A colleague questions whether your patient was monitored closely enough overnight. You feel attacked. The strongest response is the specific record of what was done.","task":"Write a 2-sentence response answering with specifics, not emotion.","tips":["Facts defuse: 'checked every two hours, labs at 4 a.m.'","Specifics answer the question; defensiveness raises new ones.","Let the record speak instead of your feelings about being asked."],"focus":["precision","impact"]},
    {"id":"pressure-doc-early-16","level":"early","profession":"doctor","title":"The trap question on rounds","scenario":"The attending asks a question designed to expose a gap: \"And if that treatment fails, then what?\" You don't have a plan B ready. Composure means answering what you can and committing to fill the gap.","task":"Write a response that gives your best answer and flags what you'll confirm.","tips":["Offer your best plan B, even if incomplete.","'My next step would be X — let me confirm the dosing.'","Partial-with-a-plan beats blank."],"focus":["clarity","structure"]},
    {"id":"pressure-doc-early-17","level":"early","profession":"doctor","title":"The interruption mid-answer","scenario":"You're answering when the attending interrupts with a follow-up before you finish. You lose your thread. The move is to address the new question, then return to your point cleanly.","task":"Write a response that handles the interruption and returns to the original point.","tips":["Answer the interruption, then 'to finish my earlier point...'","Losing the thread reads as not having one.","You can hold two questions and answer both in order."],"focus":["structure","clarity"]},
    {"id":"pressure-doc-early-18","level":"early","profession":"doctor","title":"The uncomfortable statistic","scenario":"A patient asks the survival odds for their condition. The number isn't good. You're tempted to fudge it. Answering honestly, in context, is what they asked for.","task":"Write a 2-3 sentence answer that gives the honest number with context.","tips":["Give the number they asked for; don't fudge it.","Frame it with context: what the number does and doesn't predict.","Honesty with compassion beats a comforting lie."],"focus":["precision","audience"]},
    {"id":"pressure-doc-early-19","level":"early","profession":"doctor","title":"The senior's rapid escalation question","scenario":"You escalate a concern and the senior fires back, \"What do you want me to do about it?\" You hadn't formed a clear ask. Composure is naming the specific action you need, on the spot.","task":"Write a direct 1-2 sentence answer naming what you need.","tips":["Have the ask ready: 'come see her' or 'a phone order for X'.","'What do you want' deserves a specific answer, not a restatement.","Escalating without an ask invites this exact question."],"focus":["clarity","impact"],"placeholder":"I'd like you to come assess her with me in the next fifteen minutes."},
    {"id":"pressure-doc-early-20","level":"early","profession":"doctor","title":"The family's 'you promised'","scenario":"A family says you promised something you didn't quite say. You feel cornered. The move is to clarify calmly what was actually said and re-anchor on the current plan.","task":"Write a 2-sentence response that clarifies without accusing them of misremembering.","tips":["Re-anchor gently: 'What I can tell you now is X.'","Don't litigate who said what — refocus on the plan.","Calm clarity defuses a cornered feeling on both sides."],"focus":["clarity","audience"]},
    {"id":"pressure-doc-early-21","level":"early","profession":"doctor","title":"The question outside your knowledge","scenario":"A patient asks a detailed question about a specialty area you don't know well. Guessing would be dangerous. The move is to say so honestly and route them to the answer.","task":"Write a 2-sentence response that admits the limit and names who will answer.","tips":["'That's outside my area, so I won't guess — I'll get the specialist.'","Honest routing beats a confident wrong answer.","Naming who WILL answer keeps it from feeling like a brush-off."],"focus":["clarity","audience"]},
    {"id":"pressure-doc-early-22","level":"early","profession":"doctor","title":"The heated disagreement between teams","scenario":"In a joint discussion, another team's resident challenges your plan aggressively. You could match the heat or stay composed. Composure with substance wins the room.","task":"Write a 2-sentence composed response that engages the substance, not the tone.","tips":["Lower the temperature; answer the argument, not the attack.","'Fair point — here's why I'd still do X.'","Staying composed while they escalate reads as command."],"focus":["clarity","impact"]},
    {"id":"pressure-doc-early-23","level":"early","profession":"doctor","title":"The patient who caught an inconsistency","scenario":"A patient notes that you and another doctor said different things. You feel exposed. The move is to acknowledge the inconsistency honestly and clarify the actual current plan.","task":"Write a 2-sentence response that owns the mixed message and clarifies.","tips":["Acknowledge it: 'I can see why that's confusing.'","Then state the single current plan clearly.","Owning the mixed message rebuilds the trust it dented."],"focus":["clarity","audience"]},
    {"id":"pressure-doc-early-24","level":"early","profession":"doctor","title":"The 'just give me a number'","scenario":"A patient presses for a specific timeframe you can only estimate. You keep hedging and they get frustrated. The move is to give an honest range with the caveat, not endless hedging.","task":"Write a 2-sentence answer with an honest range and one caveat.","tips":["Give a range: 'usually two to four days, sometimes longer.'","One caveat, not five — the range already carries the uncertainty.","Endless hedging frustrates more than an honest estimate."],"focus":["precision","audience"]},
    {"id":"pressure-doc-early-25","level":"early","profession":"doctor","title":"The morbidity conference cross-examination","scenario":"At a case conference, senior physicians probe your overnight decisions one after another. You need to answer each directly, own the gaps, and not crumble or get defensive across the whole exchange.","task":"Write a 3-sentence stretch answering a probing question directly, owning one gap, and holding composure.","tips":["Answer each question on its own terms, directly.","Own the one real gap without over-apologizing.","Composure across a long grilling is the skill being tested."],"focus":["clarity","impact"]}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-doc-early-01","level":"early","profession":"doctor","title":"Selling the lifestyle change","scenario":"You need your patient with early diabetes to change his diet, but 'you should eat better' hasn't moved him. A before-and-after story of where he's headed versus where he could be would land harder.","task":"Write a 3-4 sentence pitch framing the change as a fork between two futures.","tips":["Paint the two paths: staying the course versus changing now.","Make the better future concrete — what his life looks like.","Persuasion is a story about him, not a lecture about food."],"focus":["impact","audience"]},
    {"id":"narrative-doc-early-02","level":"early","profession":"doctor","title":"Concrete stakes for medication adherence","scenario":"Your patient keeps skipping her blood-pressure pills because she 'feels fine.' Abstract risk hasn't worked. You need to make the stakes concrete and personal.","task":"Write a 2-3 sentence explanation that makes the invisible risk vivid and personal.","tips":["Abstract risk doesn't move people — make it specific to her.","Connect the pill to something she cares about keeping.","'Feels fine' is exactly why the stakes must be made visible."],"focus":["impact","audience"]},
    {"id":"narrative-doc-early-03","level":"early","profession":"doctor","title":"Pre-empt the strongest objection","scenario":"You're recommending a procedure the patient is nervous about. Their biggest fear is the recovery time. If you address that head-on before they raise it, you'll win their trust.","task":"Write a 2-3 sentence pitch that names and addresses their likely objection first.","tips":["Name the fear before they do; it disarms it.","Address the strongest objection, not the easiest one.","Pre-empting shows you understand their real concern."],"focus":["impact","audience"]},
    {"id":"narrative-doc-early-04","level":"early","profession":"doctor","title":"The case for admitting the patient","scenario":"You need to persuade the reluctant medicine team to admit a borderline patient. A flat list of findings hasn't convinced them. A narrative of what happens if he goes home would.","task":"Write a 3-sentence persuasive case built around the risk of the wrong call.","tips":["Frame the downside of discharging: the story that could unfold.","One vivid consequence beats five neutral data points.","Persuasion is helping them see the risk you already see."],"focus":["impact","structure"]},
    {"id":"narrative-doc-early-05","level":"early","profession":"doctor","title":"The teaching case as a story","scenario":"You're presenting a case at conference to teach a lesson about a missed diagnosis. Presented as a data dump, no one remembers it. Told as a story with a turn, it sticks.","task":"Write a 3-4 sentence narrative arc: normal, the missed clue, the reveal, the lesson.","tips":["Build to the turn — the moment the diagnosis became clear.","Concrete detail makes the lesson memorable.","A story with stakes teaches better than a list of facts."],"focus":["impact","structure"]},
    {"id":"narrative-doc-early-06","level":"early","profession":"doctor","title":"Persuading the family toward comfort care","scenario":"A family is pushing for aggressive treatment that you believe will only prolong suffering. You need to gently reframe the goal from 'fighting' to 'comfort and time,' honoring their love.","task":"Write a 3-sentence reframe that shifts the story without dismissing their hope.","tips":["Honor the love behind their fight before reframing.","Reframe 'giving up' as 'a different kind of care'.","The story is about her comfort, not your recommendation."],"focus":["impact","audience"]},
    {"id":"narrative-doc-early-07","level":"early","profession":"doctor","title":"The before-and-after for physical therapy","scenario":"Your post-surgery patient is skipping physical therapy because it hurts. You need him to see the therapy as the bridge from where he is to walking unaided again.","task":"Write a 2-3 sentence pitch framing therapy as the path between two versions of his recovery.","tips":["Contrast the two outcomes: therapy now versus stiffness later.","Make the payoff concrete — what he'll be able to do.","The pain is the cost of the better ending; name the ending."],"focus":["impact","audience"]},
    {"id":"narrative-doc-early-08","level":"early","profession":"doctor","title":"Making the case to the attending for a plan change","scenario":"You want the attending to switch the patient's antibiotics based on new information. A bare recommendation might get waved off. A short narrative of why the picture changed will persuade.","task":"Write a 3-sentence case: what we thought, what changed, why the new plan follows.","tips":["Frame the change as a response to new evidence, not a whim.","'We started X assuming Y; now we know Z' tells the story.","The narrative makes your recommendation feel inevitable."],"focus":["impact","structure"]},
    {"id":"narrative-doc-early-09","level":"early","profession":"doctor","title":"The smoking-cessation nudge","scenario":"Your patient has heard 'you should quit smoking' a hundred times and tunes it out. You need a fresh, concrete frame that connects to something he actually cares about.","task":"Write a 2-3 sentence pitch anchored to a personal, concrete stake.","tips":["Skip the generic warning; find his specific reason.","Anchor to what he values — a grandchild, a hobby, a goal.","A stake he feels beats a statistic he's heard."],"focus":["impact","audience"]},
    {"id":"narrative-doc-early-10","level":"early","profession":"doctor","title":"Persuading the patient to stay","scenario":"A patient wants to leave against medical advice. Lecturing him will harden his resistance. A calm story of the specific risk, plus respect for his autonomy, is your best shot.","task":"Write a 3-sentence appeal that makes the risk concrete without threatening.","tips":["Respect his autonomy while making the danger vivid.","One concrete scenario beats 'you could get seriously ill'.","Pushing harder often pushes them out the door faster."],"focus":["impact","audience"]},
    {"id":"narrative-doc-early-11","level":"early","profession":"doctor","title":"The pitch for the earlier scan","scenario":"You're persuading radiology to move up a scan. 'It's important' won't cut it. A brief narrative of the decision waiting on it makes the urgency real.","task":"Write a 2-3 sentence case that frames the scan as the linchpin of a time-sensitive decision.","tips":["Frame it as: this scan unlocks a decision we can't make without it.","Concrete consequence of delay, not generic urgency.","Persuasion is showing them why it matters to the patient today."],"focus":["impact","structure"]},
    {"id":"narrative-doc-early-12","level":"early","profession":"doctor","title":"Reframing vaccination hesitancy","scenario":"A parent is hesitant about a routine childhood vaccine. Arguing statistics has backfired before. You need to address the underlying fear and reframe the choice around protecting their child.","task":"Write a 3-sentence response that meets the fear and reframes toward their goal.","tips":["Meet the worry first; don't argue past it.","Reframe around their goal — a healthy, protected child.","Shared goal, not a debate, is the persuasive frame."],"focus":["impact","audience"]},
    {"id":"narrative-doc-early-13","level":"early","profession":"doctor","title":"Making the discharge plan appealing","scenario":"Your patient is anxious about going home and wants to stay longer, though she's medically ready. You need to frame home as the better place for her recovery, not as being pushed out.","task":"Write a 3-sentence reframe that makes going home feel safe and positive.","tips":["Reframe home as where she recovers best, with a safety net.","Name the supports so home doesn't feel like abandonment.","The story is about her getting better, not about the bed she frees up."],"focus":["impact","audience"]},
    {"id":"narrative-doc-early-14","level":"early","profession":"doctor","title":"The case for the consult, persuasively","scenario":"A consultant is reluctant to see your patient today, saying it can wait. You believe it can't. A concise narrative of what's at stake will move them better than insistence.","task":"Write a 3-sentence case that makes the stakes of waiting concrete.","tips":["Show the consequence of delay, specifically.","One vivid stake beats repeating 'it's urgent'.","Persuade by aligning on the patient's risk, not by pulling rank."],"focus":["impact","clarity"]},
    {"id":"narrative-doc-early-15","level":"early","profession":"doctor","title":"Motivating the anxious pre-op patient","scenario":"Your patient is so frightened of surgery he's considering canceling. You need to reframe the surgery as the path out of the problem that's been limiting him, and address the fear honestly.","task":"Write a 3-sentence reframe that acknowledges fear and paints the after.","tips":["Acknowledge the fear; don't minimize it.","Paint the 'after' — life without the problem.","The narrative bridges from the scary now to the better then."],"focus":["impact","audience"]},
    {"id":"narrative-doc-early-16","level":"early","profession":"doctor","title":"The pitch for a follow-up appointment","scenario":"Your patient doesn't see the point of a follow-up since he 'feels fine.' You need to frame the visit as catching problems while they're still easy to fix, not as a formality.","task":"Write a 2-3 sentence pitch that makes the follow-up feel worth his time.","tips":["Frame it as staying ahead of a problem, not a check-box.","Concrete value: what the visit catches or prevents.","'Feels fine' is the argument FOR the visit, not against it."],"focus":["impact","audience"]},
    {"id":"narrative-doc-early-17","level":"early","profession":"doctor","title":"Selling the safer, slower option","scenario":"A patient wants the fastest fix, but you recommend a slower, safer approach. You need to make the case for patience compelling, not just correct.","task":"Write a 3-sentence pitch that makes the slower path feel like the smarter choice.","tips":["Frame slow as deliberate, not passive.","Contrast the fast path's hidden risk with the safe path's payoff.","Make patience feel like winning, not waiting."],"focus":["impact","clarity"]},
    {"id":"narrative-doc-early-18","level":"early","profession":"doctor","title":"The team-buy-in for a new protocol","scenario":"You want the nursing team to adopt a new checklist that adds a small step. They see only the extra work. You need to frame it around the error it prevents, with a concrete example.","task":"Write a 3-sentence pitch that frames the change around a real prevented harm.","tips":["Lead with the harm it prevents, made concrete.","Acknowledge the extra step honestly — then the payoff.","One story of a near-miss beats a policy memo."],"focus":["impact","audience"]},
    {"id":"narrative-doc-early-19","level":"early","profession":"doctor","title":"Persuading the patient to accept help at home","scenario":"An independent elderly patient refuses a home aide, seeing it as losing independence. You need to reframe the aide as what KEEPS her independent and at home.","task":"Write a 3-sentence reframe that turns the help into a form of independence.","tips":["Reframe: the aide is how she stays home, not loses control.","Address the real fear — loss of self — directly.","The story is her keeping her life, with a little support."],"focus":["impact","audience"]},
    {"id":"narrative-doc-early-20","level":"early","profession":"doctor","title":"The compelling case for the guideline","scenario":"You're arguing to a skeptical senior that the team should follow a newer guideline. A citation alone won't persuade. A narrative of why the old approach falls short here will.","task":"Write a 3-sentence case contrasting the old approach's gap with the new one's fix.","tips":["Show where the old way fails this patient.","Then how the new guideline closes that gap.","Persuade with the specific case, not just the reference."],"focus":["impact","structure"]},
    {"id":"narrative-doc-early-21","level":"early","profession":"doctor","title":"Making the abstract test result matter","scenario":"Your patient shrugs at a concerning cholesterol result because it's just a number. You need to translate the number into a story about his heart over the next decade.","task":"Write a 2-3 sentence explanation that turns the number into a personal trajectory.","tips":["Numbers don't scare; trajectories do — show the path.","Connect the result to a future he can picture.","End with the fork: what changes if he acts now."],"focus":["impact","audience"]},
    {"id":"narrative-doc-early-22","level":"early","profession":"doctor","title":"The appeal to the on-call specialist","scenario":"It's late and you need an on-call specialist to come in. They'd rather manage by phone. A concise, vivid account of why remote management isn't enough tonight will persuade.","task":"Write a 3-sentence appeal that makes in-person necessity concrete.","tips":["Name the specific thing that can't be done by phone.","Vivid over insistent — show, don't demand.","Align on the patient's risk, not on your inconvenience."],"focus":["impact","clarity"]},
    {"id":"narrative-doc-early-23","level":"early","profession":"doctor","title":"Reframing the long recovery","scenario":"A patient facing months of rehab is despairing, seeing only the long road. You need to reframe the journey into milestones that make progress feel real and achievable.","task":"Write a 3-sentence reframe that breaks the long road into a hopeful sequence.","tips":["Break the mountain into the first few steps.","Make the near milestone concrete and reachable.","The story is momentum, not the full distance at once."],"focus":["impact","audience"]},
    {"id":"narrative-doc-early-24","level":"early","profession":"doctor","title":"The pitch to enroll in the program","scenario":"You're recommending a smoking-cessation or cardiac-rehab program the patient is skeptical of. You need to pre-empt the 'I can do it myself' objection and frame the program as the edge that works.","task":"Write a 3-sentence pitch that pre-empts the objection and frames the benefit.","tips":["Name the 'I'll just do it myself' objection and answer it.","Frame the program as the thing that makes success likely.","One concrete feature that helps beats a general endorsement."],"focus":["impact","audience"]},
    {"id":"narrative-doc-early-25","level":"early","profession":"doctor","title":"The full persuasive case at the family meeting","scenario":"You're leading a family toward a difficult decision about their relative's care. You need to set the frame, make the stakes concrete, and pre-empt their strongest objection — all with compassion.","task":"Write a 4-sentence persuasive arc: current picture, the fork ahead, the stakes, the objection addressed.","tips":["Set the honest picture, then the two paths.","Make the stakes concrete and human.","Name their likely objection before they raise it, gently."],"focus":["impact","audience"]}
  ],
  "delivering-hard-messages": [
    {"id":"hard-doc-early-01","level":"early","profession":"doctor","title":"Front-load the bad news","scenario":"You have to tell a patient the biopsy found cancer. Your instinct is to warm up with the procedure details and lab process first. Clear is kind: the news should come near the front, gently but plainly.","task":"Write a 2-3 sentence opening that delivers the news early and humanely.","tips":["Don't bury the headline under process — it prolongs the dread.","A brief warning shot, then the news, plainly.","Clear is kind; vagueness here is cruelty dressed as gentleness."],"focus":["clarity","audience"],"placeholder":"I have some difficult news, and I want to tell you directly: the biopsy showed cancer."},
    {"id":"hard-doc-early-02","level":"early","profession":"doctor","title":"The clean no to a request","scenario":"A patient demands antibiotics you won't prescribe. You keep softening the 'no' until it sounds like a 'maybe,' which prolongs the argument. A clean, kind no serves better.","task":"Write a 2-sentence clear 'no' with the reason, no false hope.","tips":["Say no clearly; a soft no invites negotiation.","Give the reason once, then hold the line kindly.","Ambiguity here wastes both your time and his."],"focus":["clarity","impact"],"placeholder":"I'm not going to prescribe antibiotics for this, and here's why:"},
    {"id":"hard-doc-early-03","level":"early","profession":"doctor","title":"Behavior, impact, ask — to a colleague","scenario":"A co-resident keeps signing out incomplete notes, and it's landing on you. You need to give feedback using behavior, impact, ask — not vague frustration or a personal jab.","task":"Write a 3-sentence feedback message: the behavior, its impact, the ask.","tips":["Name the specific behavior, not the person's character.","State the concrete impact on you or the patient.","End with a clear, doable ask."],"focus":["clarity","structure"]},
    {"id":"hard-doc-early-04","level":"early","profession":"doctor","title":"Telling the family recovery won't be full","scenario":"A family expects their relative to return to normal, but she won't — there'll be lasting deficits. You need to deliver this honestly rather than let them keep hoping for something that won't come.","task":"Write a 3-sentence honest message about the realistic outcome, delivered with care.","tips":["Honesty about the ceiling is kinder than false hope.","State the realistic picture plainly, then what's still possible.","Let them grieve the gap rather than discover it later."],"focus":["clarity","audience"]},
    {"id":"hard-doc-early-05","level":"early","profession":"doctor","title":"Admitting the error to the patient","scenario":"A medication error affected your patient, and you need to disclose it. The urge is to minimize or bury it in qualifiers. An honest, direct disclosure is both right and required.","task":"Write a 3-sentence disclosure: what happened, the effect, what you're doing about it.","tips":["State the error plainly; minimizing reads as evasion.","Name the actual effect honestly.","Follow with the concrete step you're taking now."],"focus":["clarity","impact"],"placeholder":"I need to tell you about a mistake in your care and what we're doing about it."},
    {"id":"hard-doc-early-06","level":"early","profession":"doctor","title":"The no to a family's demand for a transfer","scenario":"A family demands transfer to a bigger hospital when it isn't warranted or safe. You need to decline clearly and explain why, without hiding behind bureaucracy.","task":"Write a 2-3 sentence clear decline with the honest reason.","tips":["Decline clearly; don't blame 'policy' for a clinical judgment.","One honest reason, delivered with respect.","A wobbly no here means the argument continues."],"focus":["clarity","audience"]},
    {"id":"hard-doc-early-07","level":"early","profession":"doctor","title":"Telling a patient they can't drive","scenario":"Your patient's condition legally bars them from driving, which upends their independence. You need to deliver this clearly, acknowledge the loss, and not soften it into ambiguity.","task":"Write a 3-sentence message that states the restriction, acknowledges the cost, and stays firm.","tips":["State the restriction plainly — ambiguity is dangerous here.","Acknowledge what it costs them; don't pretend it's small.","Firm and compassionate, not firm and cold."],"focus":["clarity","audience"]},
    {"id":"hard-doc-early-08","level":"early","profession":"doctor","title":"Feedback to the medical student","scenario":"Your student's patient presentations are disorganized and running long. You need to give corrective feedback that's specific and useful, not a vague 'be more concise' or a discouraging blow.","task":"Write a 3-sentence feedback: the specific issue, its effect, and one concrete change.","tips":["Specific beats 'be more concise' — name what to change.","Frame the impact: what disorganization costs on rounds.","One concrete, doable change she can apply tomorrow."],"focus":["clarity","structure"]},
    {"id":"hard-doc-early-09","level":"early","profession":"doctor","title":"Delivering a poor prognosis","scenario":"You need to tell a patient their disease has progressed and treatment options are narrowing. The temptation is euphemism. Clear, gentle honesty is what respects them.","task":"Write a 3-sentence message that delivers the prognosis honestly and stays present.","tips":["Euphemism robs them of the truth they need to plan.","Plain words, gentle delivery, no false optimism.","Stay in the room after — don't deliver and flee."],"focus":["clarity","audience"]},
    {"id":"hard-doc-early-10","level":"early","profession":"doctor","title":"The no to a colleague's favor","scenario":"A senior colleague asks you to bend a protocol as a favor, and you shouldn't. You need to decline respectfully but clearly, without damaging the relationship or caving.","task":"Write a 2-3 sentence respectful decline that holds the line.","tips":["Decline the ask, not the person.","Name the reason it matters — patient safety, not rigidity.","Respectful and firm can coexist."],"focus":["clarity","impact"]},
    {"id":"hard-doc-early-11","level":"early","profession":"doctor","title":"Telling the family visiting must end","scenario":"A family is refusing to leave past visiting hours and it's affecting the patient's rest and other patients. You need to deliver the limit clearly and kindly, not apologetically or harshly.","task":"Write a 2-3 sentence message that sets the limit with warmth and firmness.","tips":["State the limit clearly; over-apologizing weakens it.","Explain the why — the patient's rest — so it's not arbitrary.","Warm and firm, not either alone."],"focus":["clarity","audience"]},
    {"id":"hard-doc-early-12","level":"early","profession":"doctor","title":"Owning up to the attending about missed work","scenario":"You didn't complete a task you were assigned, and the attending will find out. You need to tell her before she discovers it, plainly, without a wall of excuses.","task":"Write a 2-3 sentence disclosure that owns the miss and states the recovery plan.","tips":["Lead with the fact: I didn't get X done.","One line of honest reason, not a pile of excuses.","End with how you'll fix it and by when."],"focus":["clarity","impact"],"placeholder":"I need to tell you I didn't finish the discharge summaries — here's what happened and my plan."},
    {"id":"hard-doc-early-13","level":"early","profession":"doctor","title":"Breaking difficult news over the phone","scenario":"You have to call a family member to say their relative has taken a serious turn. Phone breaks much of the warmth you'd have in person, so your words have to carry the care.","task":"Write a 3-sentence phone opening that delivers the news clearly and compassionately.","tips":["A brief warning, then the news — don't stretch the dread.","On the phone, tone and pacing do the work of presence.","Offer to have them come in, or a next call, so they're not alone with it."],"focus":["clarity","audience"]},
    {"id":"hard-doc-early-14","level":"early","profession":"doctor","title":"The honest 'we don't have an answer'","scenario":"After extensive workup, you still can't explain the patient's symptoms. They want a diagnosis you can't give. You need to deliver this uncertainty honestly rather than invent a label.","task":"Write a 3-sentence message that admits the uncertainty and gives a path forward.","tips":["Don't invent a diagnosis to fill the silence.","Honest uncertainty with a plan beats a false label.","Name what you'll keep doing so it's not a dead end."],"focus":["clarity","audience"]},
    {"id":"hard-doc-early-15","level":"early","profession":"doctor","title":"Declining the inappropriate prescription refill","scenario":"A patient requests a refill of a controlled medication you have concerns about continuing. You need to say no clearly, explain, and offer a safer path, without accusation.","task":"Write a 3-sentence response: the clear no, the reason, the alternative.","tips":["Clear no, then the safety reason, then a real alternative.","Avoid an accusatory tone; keep it about the medicine.","An offered alternative keeps 'no' from being a wall."],"focus":["clarity","impact"]},
    {"id":"hard-doc-early-16","level":"early","profession":"doctor","title":"Feedback to the nurse about a delay","scenario":"A nurse delayed reporting a change that mattered. You need to raise it as a learning conversation using behavior-impact-ask, not as blame, since you'll keep working together.","task":"Write a 3-sentence feedback that names the behavior, impact, and future ask.","tips":["Behavior: the specific delay, not 'you're careless'.","Impact: what it meant for the patient.","Ask: what you'd like next time, concretely."],"focus":["clarity","structure"]},
    {"id":"hard-doc-early-17","level":"early","profession":"doctor","title":"Telling the patient the surgery was more complicated","scenario":"The operation revealed more than expected and the recovery will be harder than promised. You need to deliver this honestly to a patient who was told to expect a simple course.","task":"Write a 3-sentence message that updates the expectation honestly and supportively.","tips":["Update the picture plainly — don't let them find out slowly.","Acknowledge the gap from what they were told.","Pair the hard news with the concrete support plan."],"focus":["clarity","audience"]},
    {"id":"hard-doc-early-18","level":"early","profession":"doctor","title":"The no to more of your time","scenario":"A patient wants to keep extending the visit with new topics while others wait. You need to close the visit kindly but clearly, without seeming to dismiss them.","task":"Write a 2-3 sentence close that ends the visit warmly and firmly.","tips":["Name what you covered, then draw the line kindly.","Offer the next channel — a follow-up — so it's not a shutdown.","Firm close, warm tone; both matter."],"focus":["clarity","audience"]},
    {"id":"hard-doc-early-19","level":"early","profession":"doctor","title":"Disclosing a delay in diagnosis","scenario":"A diagnosis was missed on an earlier visit and caught now. You need to be honest with the patient about the delay, without either over-blaming yourself or minimizing.","task":"Write a 3-sentence honest disclosure that's neither defensive nor self-flagellating.","tips":["State the delay factually; don't spin or grovel.","Acknowledge the impact honestly.","Focus on the plan from here, which is what they need."],"focus":["clarity","impact"]},
    {"id":"hard-doc-early-20","level":"early","profession":"doctor","title":"Telling the family it's time for hospice","scenario":"You believe further treatment won't help and hospice is the right path, but the family hears 'giving up.' You need to deliver this hard message with clarity and compassion, reframing care not abandonment.","task":"Write a 3-sentence message that delivers the recommendation clearly and compassionately.","tips":["Name hospice plainly, then reframe it as active comfort care.","Acknowledge that it's a hard thing to hear.","Clear is kind: don't leave them guessing what you mean."],"focus":["clarity","audience"]},
    {"id":"hard-doc-early-21","level":"early","profession":"doctor","title":"The peer feedback you've been avoiding","scenario":"A co-resident's tone with nurses has been a problem, and you're the one who should say something. You've avoided it. You need a direct, kind behavior-impact-ask conversation.","task":"Write a 3-sentence feedback opener that's direct and non-accusatory.","tips":["Open with care for them, then the specific behavior.","Impact on the team, stated factually.","One clear ask, framed as help not judgment."],"focus":["clarity","structure"]},
    {"id":"hard-doc-early-22","level":"early","profession":"doctor","title":"Saying no to a test the patient insists on","scenario":"A patient insists on an expensive scan that isn't indicated and could cause harm through false positives. You need to decline clearly, explain the real reason, and not cave to pressure.","task":"Write a 3-sentence decline that explains why the test isn't right, kindly.","tips":["Decline clearly; explain the harm of unnecessary testing.","Make it about their well-being, not cost or rules.","Hold the line kindly — a soft no invites more pressure."],"focus":["clarity","impact"]},
    {"id":"hard-doc-early-23","level":"early","profession":"doctor","title":"Delivering the unexpected finding","scenario":"A scan done for one reason revealed something serious and unrelated. You need to tell the patient about a finding they weren't braced for, clearly and without panicking them.","task":"Write a 3-sentence message that delivers the finding calmly and states the next step.","tips":["A brief warning, then the finding, plainly.","Calm delivery keeps them from spiraling.","End with the concrete next step so it's not just fear."],"focus":["clarity","audience"]},
    {"id":"hard-doc-early-24","level":"early","profession":"doctor","title":"Telling your senior you disagree","scenario":"You believe your senior's plan is wrong and potentially unsafe. Raising it is uncomfortable, but you need to voice the disagreement clearly and respectfully, not swallow it.","task":"Write a 3-sentence message that raises the concern directly and respectfully.","tips":["State the concern plainly — safety over comfort.","Frame it as a question or observation, not an accusation.","Respectful and clear; don't bury the concern in hedges."],"focus":["clarity","impact"]},
    {"id":"hard-doc-early-25","level":"early","profession":"doctor","title":"The full hard conversation with the family","scenario":"You must tell a family their relative is dying, that the treatment isn't working, and what the options now are. This is the hardest conversation, and it needs to be clear, front-loaded, and humane throughout.","task":"Write a 4-sentence arc: the warning, the news, the honest picture, the path forward.","tips":["A brief warning shot, then the news, without delay.","The honest picture — plainly, no euphemism.","End on the path: what you can still do for comfort and time."],"focus":["clarity","audience"]}
  ],
  "putting-it-together": [
    {"id":"together-doc-early-01","level":"early","profession":"doctor","title":"The complete morning presentation","scenario":"You're presenting a complex new admission on rounds: lead with the point, structure it, keep it concise, be precise, and recommend a plan — all in under ninety seconds, with the attending on a tight schedule.","task":"Write a 4-5 sentence presentation that leads, structures, and lands a recommendation.","tips":["Assessment first, then the two or three problems that matter.","Precise numbers only where they change the plan.","End with your recommendation, owned."],"focus":["structure","impact"]},
    {"id":"together-doc-early-02","level":"early","profession":"doctor","title":"The handoff under real time pressure","scenario":"Shift change, ten patients, five minutes. You need a handoff that's structured (SBAR), prioritized (sickest first), precise (real thresholds), and concise — matched to a tired colleague taking over.","task":"Write the opening and the one-line entry for your sickest patient.","tips":["Sickest first; the one-liner carries the watch instruction.","Precise trigger and precise action in the line.","Match a tired colleague: no fluff, just what to do."],"focus":["structure","concision"]},
    {"id":"together-doc-early-03","level":"early","profession":"doctor","title":"The discharge summary, done right","scenario":"You're writing a discharge summary that the next doctor will actually rely on. It needs a clear arc, precise details, no bloat, and language pitched to a colleague — all at once.","task":"Write the 2-3 sentence opening that a busy next reader can act on in seconds.","tips":["Lead with the arc: why in, what done, how out.","Precise on the things that matter for follow-up.","Cut the day-by-day; that's what the body is for."],"focus":["structure","concision"]},
    {"id":"together-doc-early-04","level":"early","profession":"doctor","title":"The family update that does everything","scenario":"You're updating an anxious family after a rough night. You need to lead with reassurance, translate the medicine, be honest and precise, and end with what's next — matched to their fear, not your chart.","task":"Write a 3-4 sentence update that reassures, translates, and orients.","tips":["Headline where things stand, in plain words.","Honest about the night without drowning them in detail.","End with the concrete next step so they have something to hold."],"focus":["audience","clarity"]},
    {"id":"together-doc-early-05","level":"early","profession":"doctor","title":"The consult request, fully polished","scenario":"You're paging a consultant during a busy day. Your request must lead with the question, give only relevant context, be precise, and respect their time — the whole toolkit in one message.","task":"Write a 3-4 sentence consult request that a busy consultant can triage instantly.","tips":["Question first, then the two facts that bear on it.","Precise on what you've already done and ruled out.","Nothing the chart already holds — point, don't paste."],"focus":["structure","concision"]},
    {"id":"together-doc-early-06","level":"early","profession":"doctor","title":"Match the channel: page vs. call vs. message","scenario":"You have three things to communicate: an urgent deterioration, a routine order change, and a non-urgent question. Each needs a different channel and register — a page, a message, an email.","task":"Write the one-line version of each, matched to its right channel.","tips":["Urgent goes to the fastest channel, framed as an ask.","Routine order change: a clear message, no urgency theater.","Non-urgent question: async, low-pressure, patient.","Register follows channel — match the medium to the message."],"focus":["audience","concision"]},
    {"id":"together-doc-early-07","level":"early","profession":"doctor","title":"Edit your own note like a reader","scenario":"You've drafted an admission note that's accurate but bloated, buries the assessment, and mixes fact with judgment. Reread it as the attending will and fix the three worst problems.","task":"Name the three edits you'd make and rewrite the assessment line.","tips":["Read as the tired reader, not the proud author.","Surface the assessment; cut the bloat; split fact from judgment.","The rewrite should lead with your read, cleanly."],"focus":["structure","concision"]},
    {"id":"together-doc-early-08","level":"early","profession":"doctor","title":"The escalation that has to land","scenario":"You're escalating a deteriorating patient to a senior who's mid-procedure and hard to reach. You need concern, evidence, and a specific ask — led, structured, precise, concise — in the few seconds you'll get.","task":"Write a 3-sentence escalation that leads with the ask and backs it fast.","tips":["Ask first: come now, or a phone order.","Two precise findings as evidence.","No windup — you have seconds, not minutes."],"focus":["structure","impact"],"placeholder":"I need you to come see bed 7 now — she's crashing. Here's what I have:"},
    {"id":"together-doc-early-09","level":"early","profession":"doctor","title":"The patient education that sticks","scenario":"You're teaching a newly diagnosed patient to manage their condition at home. It must be structured, plain-language, precise on the actions, and matched to a nervous person who'll try to remember it later.","task":"Write a 3-4 sentence explanation structured as what, when, and warning signs.","tips":["Structure it: what to do, when, what to watch for.","Plain words and precise actions, not vague advice.","End with the two signs that should trigger a call."],"focus":["audience","structure"]},
    {"id":"together-doc-early-10","level":"early","profession":"doctor","title":"The hard news, fully delivered","scenario":"You're breaking difficult news to a patient: front-load it, be clear and precise, stay present, and end with a path. Every skill from the course converges in this one conversation.","task":"Write a 3-4 sentence arc: warning, news, honest picture, next step.","tips":["Brief warning, then the news near the front.","Clear and precise, no euphemism.","Stay present, then name the concrete next step."],"focus":["clarity","audience"]},
    {"id":"together-doc-early-11","level":"early","profession":"doctor","title":"The multidisciplinary huddle summary","scenario":"You're summarizing a patient for a room of nurses, pharmacists, and social workers, each needing something different. You must structure it, pitch to a mixed audience, and land the shared plan concisely.","task":"Write a 3-sentence summary that gives each role its cue within one plan.","tips":["One governing plan, with a cue for each role inside it.","Pitch to the mixed room, not just the doctors.","Concise enough that a busy huddle stays with you."],"focus":["audience","structure"]},
    {"id":"together-doc-early-12","level":"early","profession":"doctor","title":"The recommendation email to the attending","scenario":"You're emailing the attending overnight about a decision that can wait until morning but needs her input. It should lead with the decision, give the tradeoff concisely, be precise, and own a recommendation.","task":"Write a 3-sentence email: the decision needed, the tradeoff, your recommendation.","tips":["Lead with the decision and that it's for the morning.","One-line tradeoff, precise.","Own your recommendation; don't just present the fork."],"focus":["impact","concision"]},
    {"id":"together-doc-early-13","level":"early","profession":"doctor","title":"Answering the family's hardest question, live","scenario":"In a family meeting, someone asks the question you hoped to avoid. You must answer it directly, honestly, with the right register, staying composed — integrating pressure, precision, and audience all at once.","task":"Write a 2-3 sentence response that answers directly, honestly, and stays present.","tips":["Answer the question asked, first and plainly.","Honest and precise, matched to their fear.","Composure and presence — don't retreat into logistics."],"focus":["clarity","audience"]},
    {"id":"together-doc-early-14","level":"early","profession":"doctor","title":"The clinic note that serves three readers","scenario":"Your clinic note will be read by you next visit, a covering colleague, and possibly the patient through the portal. You need structure, precision, and a register that works for all three without bloat.","task":"Write the 2-3 sentence assessment-and-plan that serves all three readers.","tips":["Structure and precision serve the clinician readers.","Plain-enough language survives a portal read.","Concise so future-you can scan it in seconds."],"focus":["structure","audience"]},
    {"id":"together-doc-early-15","level":"early","profession":"doctor","title":"The rapid recommendation between cases","scenario":"The attending catches you in the hall with thirty seconds and asks about a tricky patient. You need to lead, structure, be precise, and own a recommendation — the whole course compressed into half a minute.","task":"Write a 2-3 sentence answer that leads, supports, and recommends, fast.","tips":["Recommendation first; the hall isn't for a full presentation.","One precise supporting fact.","Own it — thirty seconds rewards a decision, not a menu."],"focus":["impact","concision"]},
    {"id":"together-doc-early-16","level":"early","profession":"doctor","title":"The safety concern raised well","scenario":"You've spotted a systems problem that could harm patients and need to raise it with your supervisor. It must be structured, precise, own a proposed fix, and be pitched to someone who can act — everything together.","task":"Write a 3-sentence message: the problem, the risk, your proposed fix.","tips":["Frame with SCQA: the situation, what breaks it, the ask.","Precise on the risk — a concrete scenario, not a worry.","Propose a fix; don't just report the problem."],"focus":["structure","impact"]},
    {"id":"together-doc-early-17","level":"early","profession":"doctor","title":"The nursing message that prevents an error","scenario":"You're messaging the night nurse a change that, if missed, could harm the patient. It must lead with the action, be precise, structured as a checklist, and matched to a busy nurse mid-shift.","task":"Write a 2-3 sentence message that leads with the action and makes it hard to miss.","tips":["Action first, then the precise trigger and threshold.","Structure it so the key step can't be overlooked.","Match a busy nurse: scannable, no buried instructions."],"focus":["clarity","precision"],"placeholder":"Important change: hold the 6 a.m. insulin and recheck her sugar first — here's why."},
    {"id":"together-doc-early-18","level":"early","profession":"doctor","title":"The persuasive case to keep the patient","scenario":"You need to persuade the team not to discharge a borderline patient. Integrate everything: lead with your recommendation, structure the case, make the risk concrete, and pre-empt the counterargument.","task":"Write a 4-sentence case: recommendation, structured reasons, concrete stake, objection addressed.","tips":["Lead with the recommendation, then the reasons.","Make the risk of the wrong call concrete.","Pre-empt the 'he looks fine' objection directly."],"focus":["impact","structure"]},
    {"id":"together-doc-early-19","level":"early","profession":"doctor","title":"The teaching moment, fully realized","scenario":"You're teaching an intern at the bedside: structure the lesson, pitch it to their level, be precise, and keep it concise so it's usable tomorrow. All the skills, aimed at a learner.","task":"Write a 3-sentence teaching point: the principle, the case example, the takeaway.","tips":["Principle first, then this case as the example.","Pitch to the intern's level — the reusable rule.","Concise enough to survive to tomorrow's rounds."],"focus":["audience","structure"]},
    {"id":"together-doc-early-20","level":"early","profession":"doctor","title":"The end-of-life conversation, all skills engaged","scenario":"You're guiding a family through a goals-of-care decision. This demands hard-message delivery, narrative reframing, precise honesty, composure under emotion, and register matched to grief — the entire course, live.","task":"Write a 4-sentence stretch: honest picture, gentle reframe, the recommendation, an invitation to respond.","tips":["Honest picture, plainly, without euphemism.","Reframe from 'giving up' to 'comfort and time'.","Own a gentle recommendation, then open the floor to them."],"focus":["audience","impact"]},
    {"id":"together-doc-early-21","level":"early","profession":"doctor","title":"The admission call, fully composed","scenario":"You're calling to admit a patient from the ED. Lead with the ask, structure the story, be precise on what matters, stay concise, and be ready to answer the accepting resident's pushback — all in one call.","task":"Write the 3-sentence opening: the admission ask, the one-line story, the key detail.","tips":["'I have an admission for you' — the ask leads.","One-line story, precise on the reason for admission.","Anticipate the first pushback and have the answer ready."],"focus":["structure","impact"],"placeholder":"I have an admission for you — a 70-year-old with a leg infection failing oral antibiotics."},
    {"id":"together-doc-early-22","level":"early","profession":"doctor","title":"The self-edited portal reply","scenario":"A worried patient sent a portal message. Your draft reply answers, but it's long, jargon-laced, and buries the answer. Edit it like the anxious reader will read it, and land it in three sentences.","task":"Write the edited 2-3 sentence reply, answer first, plain and warm.","tips":["Answer in sentence one; that's what she's scanning for.","Cut the jargon and the length in half.","Warm register matched to worry, not a chart note."],"focus":["audience","concision"]},
    {"id":"together-doc-early-23","level":"early","profession":"doctor","title":"The concise, complete sign-out entry","scenario":"You're writing one patient's sign-out that must carry the situation, the watch item with a precise trigger, the if-then plan, and code status — structured and concise enough to read in ten seconds.","task":"Write the full sign-out entry for one patient with a watcher.","tips":["One line of situation, one if-then with a precise trigger.","Code status as a tag, not a sentence.","Ten-second read: structured, precise, no bloat."],"focus":["structure","precision"],"placeholder":"Bed 12, stable but watch breathing: if oxygen goes above 4L, call ICU. Full code."},
    {"id":"together-doc-early-24","level":"early","profession":"doctor","title":"The recommendation under attending scrutiny","scenario":"You present a plan; the attending pushes back hard. You must answer the pushback directly, defend your reasoning with precision, stay composed, and adjust if warranted — pressure and presence together.","task":"Write a 3-sentence response: address the pushback, defend with a specific reason, then stay open.","tips":["Address the actual objection, not around it.","Defend with a precise reason, calmly.","Stay open to adjusting — presence, not stubbornness."],"focus":["clarity","impact"]},
    {"id":"together-doc-early-25","level":"early","profession":"doctor","title":"The whole case, start to finish","scenario":"You're presenting a full case at morning report: it needs a governing idea, clean structure, precise evidence, an owned assessment, a persuasive teaching point, and a concise close — every skill from the course in one presentation.","task":"Write a 5-sentence presentation: the point, the structured story, the key evidence, your assessment, the lesson.","tips":["Open with the governing idea; the room needs the frame.","Structure the story with precise, load-bearing detail.","Close with an owned assessment and the transferable lesson."],"focus":["structure","impact"]}
  ]
};
